export default function App() {
  const [tab, setTab]               = useState("dashboard");
  const [filamentos, setFilamentos] = useState([]);
  const [movimientos, setMovs]      = useState([]);
  const [maestros, setMaestros]     = useState(MAESTROS_DEFAULT);
  const [loaded, setLoaded]         = useState(false);
  const [toast, setToast]           = useState(null);
  const [showStockMenu, setShowStockMenu] = useState(false);
  const [showNegocioMenu, setShowNegocioMenu] = useState(false);
  const [recetas, setRecetas]   = useState(() => loadLS(BIZ_KEYS.recetas, []));
  const [insumos, setInsumos]   = useState(() => loadLS(BIZ_KEYS.insumos, []));
  const [productos, setProductos] = useState(() => loadLS(BIZ_KEYS.productos, []));
  const [ventas, setVentas]     = useState(() => loadLS(BIZ_KEYS.ventas, []));
  const [proveedores, setProveedores] = useState(() => loadLS(BIZ_KEYS.proveedores, []));

  useEffect(() => {
    const f  = loadLS(DB_KEY, null);
    const m  = loadLS(MOV_KEY, []);
    const ma = loadLS(MAEST_KEY, null);
    const filData = f && f.length > 0 ? f : STOCK_INICIAL;
    if (!f || f.length === 0) saveLS(DB_KEY, STOCK_INICIAL);
    setFilamentos(filData);
    setMovs(m||[]);
    const maData = ma ? {...ma, bobinas: ma.bobinas || MAESTROS_DEFAULT.bobinas} : MAESTROS_DEFAULT;
    setMaestros(maData);
    setLoaded(true);
  }, []);

  const saveFil  = d => { setFilamentos(d); saveLS(DB_KEY, d); };
  const saveMov  = d => { setMovs(d);       saveLS(MOV_KEY, d); };
  const saveMaes = d => { setMaestros(d);   saveLS(MAEST_KEY, d); };
  const saveBiz = (key, setter) => d => { setter(d); saveLS(key, d); };
  const saveRecetas    = saveBiz(BIZ_KEYS.recetas,    setRecetas);
  const saveInsumos    = saveBiz(BIZ_KEYS.insumos,    setInsumos);
  const saveProductos  = saveBiz(BIZ_KEYS.productos,  setProductos);
  const saveVentas     = saveBiz(BIZ_KEYS.ventas,     setVentas);
  const saveProveedores = saveBiz(BIZ_KEYS.proveedores, setProveedores);

  const toast_   = msg => { setToast(msg);  setTimeout(() => setToast(null), 3000); };

  const handleVenta = venta => {
    saveVentas([...ventas, {...venta, id:uid(), fecha:new Date().toISOString()}]);
    // Discount from finished products stock
    if (venta.productoId && venta.cantidad) {
      const newP = productos.map(p =>
        p.id===venta.productoId ? {...p, stock:Math.max(0,(p.stock||0)-Number(venta.cantidad))} : p
      );
      saveProductos(newP);
    }
    toast_(`✓ Venta registrada`);
  };

  const handleRename = (lista, oldVal, newVal) => {
    const fm = { materiales:"material", tipos:"tipo", marcas:"marca", colores:"color", estantes:"estante", posiciones:"posicion" };
    const field = fm[lista];
    saveFil(filamentos.map(f => f[field]===oldVal ? {...f,[field]:newVal} : f));
    saveMov(movimientos.map(m => { const mf=field==="tipo"?"tipo_fil":field; return m[mf]===oldVal?{...m,[mf]:newVal}:m; }));
    saveMaes({...maestros,[lista]:maestros[lista].map(x=>x===oldVal?newVal:x)});
    toast_(`✓ "${oldVal}" → "${newVal}" actualizado en todos los registros`);
  };

  const handlePrecioUpdate = (marca, material, tipo, nuevoPrecio) => {
    const newFils = filamentos.map(f =>
      f.marca===marca && f.material===material && f.tipo===tipo
        ? {...f, precioUltimo: nuevoPrecio}
        : f
    );
    saveFil(newFils);
    const count = newFils.filter(f=>f.marca===marca&&f.material===material&&f.tipo===tipo).length;
    toast_(`✓ Precio de ${material} ${tipo} ${marca} actualizado a ${fmtARS(nuevoPrecio)} en ${count} filamento${count!==1?"s":""}`);
  };

  const handleAjuste = (key, nuevoStockNeto) => {
    const newFils = filamentos.map(f => f.key === key ? {...f, stockGramos: nuevoStockNeto} : f);
    saveFil(newFils);
    const fil = filamentos.find(f => f.key === key);
    saveMov([...movimientos, {id:Date.now(), tipo:"ajuste", fecha:new Date().toISOString(), key, material:fil.material, tipo_fil:fil.tipo, marca:fil.marca, color:fil.color, gramos:nuevoStockNeto}]);
    toast_(`✓ Stock de ${fil.color} ${fil.material} actualizado a ${fmtG(nuevoStockNeto)}g`);
  };

  const handleCompra = c => {
    const key = `fil_${Date.now()}`;
    const pesoTotal = c.pesoUnitario * c.cantidad;
    saveFil([...filamentos,{key,material:c.material,tipo:c.tipo,marca:c.marca,color:c.color,stockGramos:pesoTotal,precioUltimo:c.precio,pesoUnitario:c.pesoUnitario,estante:c.estante,posicion:c.posicion}]);
    saveMov([...movimientos,{id:Date.now(),tipo:"compra",fecha:new Date().toISOString(),key,material:c.material,tipo_fil:c.tipo,marca:c.marca,color:c.color,gramos:pesoTotal,precio:c.precio,cantidad:c.cantidad}]);
    toast_(`✓ ${c.cantidad} bobina${c.cantidad>1?"s":""} de ${c.color} ${c.material} agregada${c.cantidad>1?"s":""}`);
  };

  const handleImpresion = (lineas) => {
    const newFils=[...filamentos]; const newMovs=[...movimientos]; const id=Date.now();
    lineas.forEach((imp,i)=>{
      const idx=newFils.findIndex(f=>f.key===imp.key);
      if(idx>=0) newFils[idx]={...newFils[idx],stockGramos:Math.max(0,newFils[idx].stockGramos-imp.gramos)};
      const fil=filamentos.find(f=>f.key===imp.key);
      newMovs.push({id:id+i,tipo:"impresion",fecha:new Date().toISOString(),key:imp.key,material:fil.material,tipo_fil:fil.tipo,marca:fil.marca,color:fil.color,gramos:imp.gramos,grupoId:id});
    });
    saveFil(newFils); saveMov(newMovs);
    const total=lineas.reduce((a,l)=>a+l.gramos,0);
    toast_(`✓ Impresión: ${lineas.length} filamento${lineas.length>1?"s":""}, ${fmtG(total)}g en total`);
  };

  if (!loaded) return <div style={{display:"flex",alignItems:"center",justifyContent:"center",height:"100vh",background:"#0d0d0d",color:"#4b7d0b",fontFamily:"Montserrat,sans-serif",fontSize:13,letterSpacing:"0.1em",fontWeight:600}}>CARGANDO...</div>;

  return (
    <div style={{minHeight:"100vh",background:"#0d0d0d",color:"#ffffff",fontFamily:"'Montserrat',sans-serif"}}>
      <style>{CSS}</style>
      {toast && <div style={{position:"fixed",top:16,right:16,background:"#0d1a00",border:"1px solid #4b7d0b55",borderRadius:10,padding:"12px 18px",fontSize:12,color:"#6fb010",zIndex:9999,boxShadow:"0 8px 32px #00000077",maxWidth:340,fontWeight:600}}>{toast}</div>}
      <div style={{maxWidth:1060,margin:"0 auto",padding:"0 20px"}}>
        <div style={{borderBottom:"1px solid #1a1a1a",paddingTop:20}}>
          <div className="header-inner" style={{display:"flex",alignItems:"center",justifyContent:"space-between",flexWrap:"wrap",gap:8,paddingBottom:0}}>
            <img src={LOGO_SRC} alt="Lenga" style={{height:44,objectFit:"contain",marginBottom:4,background:"#0d0d0d",padding:"2px 6px",borderRadius:6}}/>
            <div className="tabs-row" style={{display:"flex",alignItems:"flex-end"}}>
              {/* Stock de filamento dropdown */}
              <div style={{position:"relative"}}>
                <button
                  className={`tab${["dashboard","compra","impresion","ajuste","historial","maestros"].includes(tab)?" on":""}`}
                  onClick={()=>setShowStockMenu(v=>!v)}
                  style={{display:"flex",alignItems:"center",gap:5}}
                >
                  Stock de filamento
                  <span style={{fontSize:9,opacity:0.6}}>{showStockMenu?"▲":"▼"}</span>
                </button>
                {showStockMenu && (
                  <div style={{position:"absolute",top:"100%",left:0,background:"#141414",border:"1px solid #252525",borderRadius:10,zIndex:200,minWidth:180,padding:"6px 0",boxShadow:"0 8px 32px #00000088"}}>
                    {[["dashboard","Dashboard"],["compra","Compra"],["impresion","Impresión"],["ajuste","Ajuste stock"],["historial","Historial"],["maestros","Maestros"]].map(([id,label])=>(
                      <button key={id}
                        onClick={()=>{setTab(id);setShowStockMenu(false);}}
                        style={{display:"block",width:"100%",textAlign:"left",background:tab===id?"#4b7d0b18":"none",border:"none",padding:"9px 18px",fontSize:12,fontWeight:600,color:tab===id?"#4b7d0b":"#666",cursor:"pointer",fontFamily:"Montserrat,sans-serif",letterSpacing:".06em",transition:"background .15s"}}
                        onMouseEnter={e=>e.target.style.background=tab===id?"#4b7d0b22":"#1a1a1a"}
                        onMouseLeave={e=>e.target.style.background=tab===id?"#4b7d0b18":"none"}
                      >{label}</button>
                    ))}
                  </div>
                )}
              </div>
              <button className={`tab${tab==="calculadora"?" on":""}`} onClick={()=>{setTab("calculadora");setShowStockMenu(false);}}>Costo de impresión</button>
              {/* Negocio dropdown */}
              <div style={{position:"relative"}}>
                <button
                  className={`tab${["recetas","insumos","productos","ventas","proveedores","finanzas"].includes(tab)?" on":""}`}
                  onClick={()=>{setShowNegocioMenu(v=>!v);setShowStockMenu(false);}}
                  style={{display:"flex",alignItems:"center",gap:5}}
                >
                  Negocio
                  <span style={{fontSize:9,opacity:0.6}}>{showNegocioMenu?"▲":"▼"}</span>
                </button>
                {showNegocioMenu && (
                  <div style={{position:"absolute",top:"100%",right:0,background:"#141414",border:"1px solid #252525",borderRadius:10,zIndex:200,minWidth:180,padding:"6px 0",boxShadow:"0 8px 32px #00000088"}}>
                    {[["recetas","🧪 Recetas"],["insumos","📦 Insumos"],["productos","🏷️ Productos"],["ventas","💰 Ventas"],["proveedores","🤝 Proveedores"],["finanzas","📊 Finanzas"]].map(([id,label])=>(
                      <button key={id}
                        onClick={()=>{setTab(id);setShowNegocioMenu(false);}}
                        style={{display:"block",width:"100%",textAlign:"left",background:tab===id?"#4b7d0b18":"none",border:"none",padding:"9px 18px",fontSize:12,fontWeight:600,color:tab===id?"#4b7d0b":"#666",cursor:"pointer",fontFamily:"Montserrat,sans-serif",letterSpacing:".06em",transition:"background .15s"}}
                        onMouseEnter={e=>e.target.style.background=tab===id?"#4b7d0b22":"#1a1a1a"}
                        onMouseLeave={e=>e.target.style.background=tab===id?"#4b7d0b18":"none"}
                      >{label}</button>
                    ))}
                  </div>
                )}
              </div>
            </div>
          </div>
        </div>
        <div style={{paddingTop:28,paddingBottom:48}}>
          {tab==="dashboard"  && <Dashboard filamentos={filamentos} movimientos={movimientos} onDelete={key=>saveFil(filamentos.filter(f=>f.key!==key))}/>}
          {tab==="compra"     && <FormCompra maestros={maestros} onSubmit={handleCompra}/>}
          {tab==="impresion"  && <FormImpresion filamentos={filamentos} onSubmit={handleImpresion}/>}
          {tab==="historial"  && <Historial movimientos={movimientos}/>}
          {tab==="ajuste"    && <AjusteStock filamentos={filamentos} maestros={maestros} onAjuste={handleAjuste} onDelete={key=>saveFil(filamentos.filter(f=>f.key!==key))}/>}
          {tab==="calculadora" && <Calculadora filamentos={filamentos}/>}
          {tab==="recetas"     && <Recetas recetas={recetas} onSave={saveRecetas} toast={toast_}/>}
          {tab==="insumos"     && <Insumos insumos={insumos} onSave={saveInsumos} toast={toast_}/>}
          {tab==="productos"   && <Productos productos={productos} recetas={recetas} onSave={saveProductos} toast={toast_}/>}
          {tab==="ventas"      && <Ventas ventas={ventas} productos={productos} onSave={handleVenta} onUpdate={v=>saveVentas_(v)} toast={toast_}/>}
          {tab==="proveedores" && <Proveedores proveedores={proveedores} insumos={insumos} onSave={saveProveedores} toast={toast_}/>}
          {tab==="finanzas"    && <Finanzas ventas={ventas} productos={productos} insumos={insumos}/>}
          {tab==="maestros"   && <Maestros maestros={maestros} filamentos={filamentos}
            onAdd={(l,v)=>{ if(l==="bobinas_update"){saveMaes({...maestros,bobinas:v});}else{const updated=[...maestros[l],v].sort((a,b)=>typeof a==="string"?a.localeCompare(b):0);saveMaes({...maestros,[l]:updated});}}}
            onDelete={(l,v)=>saveMaes({...maestros,[l]:maestros[l].filter(x=>x!==v)})}
            onRename={handleRename}
            onPrecioUpdate={handlePrecioUpdate}/>}
        </div>
      </div>
    </div>
  );
}

// ── DASHBOARD ─────────────────────────────────────────────────────────────────
function Dashboard({ filamentos, movimientos, onDelete }) {
  const totalStock      = filamentos.reduce((a,f)=>a+f.stockGramos,0);
  const valorInventario = filamentos.reduce((a,f)=>a+(f.precioUltimo/f.pesoUnitario)*f.stockGramos,0);
  const alertas  = filamentos.filter(f=>f.stockGramos>0&&f.stockGramos<STOCK_MINIMO).length;
  const agotados = filamentos.filter(f=>f.stockGramos===0).length;

  const meses = Array.from({length:6},(_,i)=>{
    const d=new Date(); d.setMonth(d.getMonth()-5+i);
    const key=`${d.getFullYear()}-${String(d.getMonth()+1).padStart(2,"0")}`;
    const label=d.toLocaleString("es-AR",{month:"short"}).toUpperCase();
    const gramos=movimientos.filter(m=>m.tipo==="impresion"&&m.fecha.startsWith(key)).reduce((a,m)=>a+m.gramos,0);
    return {label,gramos};
  });
  const maxG=Math.max(...meses.map(m=>m.gramos),1);
  const porMat=filamentos.reduce((acc,f)=>{acc[f.material]=(acc[f.material]||0)+f.stockGramos;return acc;},{});

  // Sort & filter state
  const [sortCol,setSortCol] = useState("color");
  const [sortDir,setSortDir] = useState("asc");
  const [searchColor,setSearchColor] = useState("");
  const [searchMarca,setSearchMarca] = useState("");
  const [searchMaterial,setSearchMaterial] = useState("");
  const [showSug,setShowSug]         = useState(false);

  const allColors = [...new Set(filamentos.map(f=>f.color))].sort();
  const suggestions = searchColor.length > 0
    ? allColors.filter(c=>c.toLowerCase().includes(searchColor.toLowerCase()))
    : [];

  const filtered = useMemo(()=>{
    return filamentos.filter(f=>{
      const mc = !searchColor || (f.color||"").toLowerCase().includes(searchColor.toLowerCase());
      const mm = !searchMarca || (f.marca||"").toLowerCase().includes(searchMarca.toLowerCase());
      const mt = !searchMaterial || (f.material||"").toLowerCase().includes(searchMaterial.toLowerCase());
      return mc && mm && mt;
    });
  },[filamentos,searchColor,searchMarca,searchMaterial]);

  const sorted = useMemo(()=>{
    const arr=[...filtered];
    arr.sort((a,b)=>{
      let va=a[sortCol], vb=b[sortCol];
      if(sortCol==="stockGramos"||sortCol==="precioUltimo"){ va=Number(va); vb=Number(vb); }
      else { va=String(va).toLowerCase(); vb=String(vb).toLowerCase(); }
      if(va<vb) return sortDir==="asc"?-1:1;
      if(va>vb) return sortDir==="asc"?1:-1;
      return 0;
    });
    return arr;
  },[filtered,sortCol,sortDir]);

  const toggleSort = col => {
    if(sortCol===col) setSortDir(d=>d==="asc"?"desc":"asc");
    else { setSortCol(col); setSortDir("asc"); }
  };

  const SortArrow = ({col}) => {
    if(sortCol!==col) return <span style={{color:"#2a2a2a",marginLeft:3}}>↕</span>;
    return <span style={{color:"#4b7d0b",marginLeft:3}}>{sortDir==="asc"?"↑":"↓"}</span>;
  };

  const TH = ({col,label,style={}}) => (
    <div className="sort-th" style={{fontSize:9,color:"#bbb",letterSpacing:".08em",textTransform:"uppercase",fontWeight:600,cursor:"pointer",...style}} onClick={()=>toggleSort(col)}>
      {label}<SortArrow col={col}/>
    </div>
  );

  const cols = "1.4fr 0.7fr 0.7fr 0.8fr 1fr 1.6fr 0.7fr 28px";

  return (
    <div>
      <div className="section-title">Resumen general</div>
      <div className="stats-grid" style={{display:"grid",gridTemplateColumns:"repeat(4,1fr)",gap:10,marginBottom:16}}>
        {[
          {label:"Stock total",      val:`${fmtG(totalStock/1000)} kg`,sub:`${filamentos.length} tipos`,color:"#4b7d0b"},
          {label:"Valor inventario", val:fmtARS(valorInventario),sub:"ARS estimado",color:"#4b7d0b"},
          {label:"Stock bajo",       val:alertas,  sub:"tipos < 100g",color:alertas>0?"#cc4444":"#333"},
          {label:"Agotados",         val:agotados, sub:"sin stock",   color:agotados>0?"#cc4444":"#333"},
        ].map((s,i)=>(
          <div key={i} className="card" style={{padding:18}}>
            <div style={{fontSize:26,fontWeight:800,color:s.color,letterSpacing:"-0.02em",lineHeight:1}}>{s.val}</div>
            <div style={{fontSize:10,color:"#bbb",letterSpacing:".08em",textTransform:"uppercase",marginTop:8,fontWeight:600}}>{s.label}</div>
            <div style={{fontSize:10,color:"#888",marginTop:2}}>{s.sub}</div>
          </div>
        ))}
      </div>

      {/* Extra indicators */}
      <div style={{display:"grid",gridTemplateColumns:"repeat(3,1fr)",gap:10,marginBottom:16}}>
        {(()=>{
          const impresiones = movimientos.filter(m=>m.tipo==="impresion");
          const thisMonth = new Date().toISOString().slice(0,7);
          const consumoMes = impresiones.filter(m=>m.fecha.startsWith(thisMonth)).reduce((a,m)=>a+m.gramos,0);
          const valorConsumido = impresiones.filter(m=>m.fecha.startsWith(thisMonth)).reduce((a,m)=>{
            const fil = filamentos.find(f=>f.key===m.key);
            return a + (fil ? (fil.precioUltimo/fil.pesoUnitario)*m.gramos : 0);
          },0);
          const masUsado = Object.entries(impresiones.reduce((acc,m)=>{acc[m.color]=(acc[m.color]||0)+m.gramos;return acc;},{})).sort((a,b)=>b[1]-a[1])[0];
          const costoPorGramo = filamentos.length>0
            ? filamentos.reduce((a,f)=>a+(f.precioUltimo/f.pesoUnitario),0)/filamentos.length
            : 0;
          return [
            {label:"Consumo este mes",    val:consumoMes>0?`${fmtG(consumoMes)}g`:"—",    sub:"gramos impresos",         color:"#4b7d0b"},
            {label:"Costo consumido mes", val:consumoMes>0?fmtARS(valorConsumido):"—",     sub:"en filamento",            color:"#4b7d0b"},
            {label:"Costo/g promedio",    val:`${fmtARS(costoPorGramo)}/g`,                sub:"sobre todo el inventario",color:"#4b7d0b"},
          ].map((s,i)=>(
            <div key={i} className="card" style={{padding:18}}>
              <div style={{fontSize:22,fontWeight:800,color:s.color,letterSpacing:"-0.02em",lineHeight:1}}>{s.val}</div>
              <div style={{fontSize:10,color:"#555",letterSpacing:".08em",textTransform:"uppercase",marginTop:8,fontWeight:600}}>{s.label}</div>
              <div style={{fontSize:10,color:"#333",marginTop:2}}>{s.sub}</div>
            </div>
          ));
        })()}
      </div>

      <div className="charts-grid" style={{display:"grid",gridTemplateColumns:"1fr 1fr",gap:10,marginBottom:10}}>
        <div className="card">
          <div style={{fontSize:10,color:"#444",letterSpacing:".1em",textTransform:"uppercase",marginBottom:18,fontWeight:600}}>Consumo mensual (g)</div>
          <div style={{display:"flex",gap:6,alignItems:"flex-end",height:80}}>
            {meses.map((m,i)=>(
              <div key={i} style={{flex:1,display:"flex",flexDirection:"column",alignItems:"center",gap:5}}>
                {m.gramos>0&&<div style={{fontSize:9,color:"#bbb",fontWeight:600}}>{fmtG(m.gramos)}</div>}
                <div style={{width:"100%",borderRadius:3,background:m.gramos>0?"#4b7d0b":"#1a1a1a",height:`${Math.max(m.gramos>0?8:3,(m.gramos/maxG)*60)}px`,transition:"height .6s"}}/>
                <div style={{fontSize:9,color:"#999",fontWeight:600}}>{m.label}</div>
              </div>
            ))}
          </div>
        </div>
        <div className="card">
          <div style={{fontSize:10,color:"#444",letterSpacing:".1em",textTransform:"uppercase",marginBottom:16,fontWeight:600}}>Stock por material</div>
          {Object.entries(porMat).map(([mat,g])=>(
            <div key={mat} style={{marginBottom:12}}>
              <div style={{display:"flex",justifyContent:"space-between",fontSize:12,marginBottom:5}}>
                <span style={{color:"#ddd",fontWeight:500}}>{mat}</span>
                <span style={{color:"#4b7d0b",fontWeight:600}}>{fmtG(g)}g</span>
              </div>
              <div className="bar"><div className="bar-fill" style={{width:`${Math.min(100,(g/totalStock)*100)||0}%`,background:"#4b7d0b"}}/></div>
            </div>
          ))}
          {filamentos.length===0&&<div style={{color:"#333",fontSize:12}}>Sin datos</div>}
        </div>
      </div>

      <div className="card">
        {/* Search bar */}
        <div style={{display:"grid",gridTemplateColumns:"1fr 1fr 1fr",gap:10,marginBottom:16}}>
          <div style={{position:"relative"}}>
            <div className="lbl">Buscar por color</div>
            <input className="inp" style={{padding:"8px 12px",fontSize:12}} placeholder="Ej: Negro..." value={searchColor}
              onChange={e=>{setSearchColor(e.target.value);setShowSug(true);}}
              onFocus={()=>setShowSug(true)}
              onBlur={()=>setTimeout(()=>setShowSug(false),150)}
            />
            {showSug&&suggestions.length>0&&(
              <div style={{position:"absolute",top:"100%",left:0,right:0,background:"#141414",border:"1px solid #252525",borderRadius:8,zIndex:100,maxHeight:180,overflowY:"auto",marginTop:2}}>
                {suggestions.map(s=>(
                  <div key={s} className="search-suggestion" onMouseDown={()=>{setSearchColor(s);setShowSug(false);}}>{s}</div>
                ))}
              </div>
            )}
          </div>
          <div>
            <div className="lbl">Filtrar por marca</div>
            <input className="inp" style={{padding:"8px 12px",fontSize:12}} placeholder="Ej: Grilon3..." value={searchMarca} onChange={e=>setSearchMarca(e.target.value)}/>
          </div>
          <div>
            <div className="lbl">Filtrar por material</div>
            <input className="inp" style={{padding:"8px 12px",fontSize:12}} placeholder="Ej: PLA..." value={searchMaterial} onChange={e=>setSearchMaterial(e.target.value)}/>
          </div>
        </div>
        {(searchColor||searchMarca||searchMaterial)&&(
          <div style={{marginBottom:12,display:"flex",alignItems:"center",gap:8}}>
            <span style={{fontSize:11,color:"#555"}}>{sorted.length} resultado{sorted.length!==1?"s":""}</span>
            <button onClick={()=>{setSearchColor("");setSearchMarca("");setSearchMaterial("");}} style={{fontSize:10,background:"none",border:"1px solid #333",borderRadius:4,padding:"2px 8px",color:"#666",cursor:"pointer",fontFamily:"Montserrat,sans-serif"}}>Limpiar filtros</button>
          </div>
        )}

        <div className="desktop-row" style={{display:"grid",gridTemplateColumns:cols,gap:10,padding:"0 0 10px",borderBottom:"1px solid #1e1e1e",marginBottom:2}}>
          <TH col="color"        label="Color"/>
          <TH col="material"     label="Material"/>
          <TH col="tipo"         label="Tipo"/>
          <TH col="marca"        label="Marca"/>
          <TH col="stockGramos"  label="Stock"/>
          <div style={{fontSize:9,color:"#555",letterSpacing:".08em",textTransform:"uppercase",fontWeight:600}}>Ubicación</div>
          <TH col="precioUltimo" label="Valor" style={{textAlign:"right"}}/>
          <div/>
        </div>
        <div className="mobile-sort-bar" style={{display:"none",gap:8,marginBottom:12,flexWrap:"wrap"}}>
          {[["color","Color"],["material","Material"],["stockGramos","Stock"],["precioUltimo","Valor"]].map(([col,label])=>(
            <button key={col} onClick={()=>toggleSort(col)} style={{background:sortCol===col?"#4b7d0b18":"#1a1a1a",border:`1px solid ${sortCol===col?"#4b7d0b44":"#252525"}`,borderRadius:6,padding:"5px 10px",fontSize:11,color:sortCol===col?"#4b7d0b":"#666",cursor:"pointer",fontFamily:"Montserrat,sans-serif",fontWeight:600}}>
              {label}{sortCol===col?(sortDir==="asc"?" ↑":" ↓"):""}
            </button>
          ))}
        </div>

        {sorted.length===0
          ?<div style={{color:"#333",fontSize:13,textAlign:"center",padding:"20px 0"}}>Sin resultados.</div>
          :sorted.map(f=>{
            const pct=Math.min(100,(f.stockGramos/f.pesoUnitario)*100);
            const bajo=f.stockGramos>0&&f.stockGramos<STOCK_MINIMO;
            const sc=bajo?"#cc4444":f.stockGramos===0?"#aa2222":"#4b7d0b";
            return (
              <div key={f.key}>
                <div className="desktop-row" style={{display:"grid",gridTemplateColumns:cols,gap:10,alignItems:"center",borderBottom:"1px solid #1a1a1a",padding:"12px 0"}}>
                  <div style={{fontSize:13,color:"#e0e0e0",fontWeight:600}}>{f.color}</div>
                  <div style={{fontSize:11,color:"#666",fontWeight:500}}>{f.material}</div>
                  <div style={{fontSize:10,color:"#444",fontWeight:500}}>{f.tipo}</div>
                  <div style={{fontSize:11,color:"#666",fontWeight:500}}>{f.marca}</div>
                  <div>
                    <div style={{fontSize:13,color:sc,fontWeight:700}}>{fmtG(f.stockGramos)}g{bajo&&<span style={{fontSize:9,marginLeft:4,color:"#cc4444"}}>⚠</span>}{f.stockGramos===0&&<span style={{fontSize:9,marginLeft:4}}>AGOTADO</span>}</div>
                    <div className="bar"><div className="bar-fill" style={{width:`${pct}%`,background:sc}}/></div>
                  </div>
                  <PosicionBadge posicion={f.posicion} estante={f.estante}/>
                  <div style={{fontSize:11,color:"#444",textAlign:"right",fontWeight:500}}>{fmtARS(f.precioUltimo/f.pesoUnitario*f.stockGramos)}</div>
                <button onClick={()=>{if(window.confirm(`¿Eliminás ${f.color} ${f.material} (${f.posicion})?`))onDelete(f.key);}} style={{background:"none",border:"none",cursor:"pointer",color:"#333",fontSize:14,padding:"2px 4px",borderRadius:4,transition:"color .2s"}} onMouseEnter={e=>e.target.style.color="#cc4444"} onMouseLeave={e=>e.target.style.color="#333"} title="Eliminar">×</button>
                </div>
                <div className="mobile-card" style={{borderBottom:"1px solid #1a1a1a",padding:"14px 0"}}>
                  <div style={{display:"flex",justifyContent:"space-between",alignItems:"flex-start",marginBottom:10}}>
                    <div style={{flex:1}}>
                      <div style={{fontSize:16,color:"#e0e0e0",fontWeight:700,marginBottom:6}}>{f.color}</div>
                      <div style={{display:"flex",gap:5,flexWrap:"wrap"}}>
                        <span style={{fontSize:10,color:"#888",background:"#1a1a1a",border:"1px solid #252525",borderRadius:4,padding:"2px 8px",fontWeight:600}}>{f.material}</span>
                        <span style={{fontSize:10,color:"#666",background:"#1a1a1a",border:"1px solid #252525",borderRadius:4,padding:"2px 8px"}}>{f.tipo}</span>
                        <span style={{fontSize:10,color:"#555",background:"#1a1a1a",border:"1px solid #252525",borderRadius:4,padding:"2px 8px"}}>{f.marca}</span>
                      </div>
                    </div>
                    <div style={{textAlign:"right",flexShrink:0,marginLeft:16}}>
                      <div style={{fontSize:18,color:sc,fontWeight:800,lineHeight:1}}>{fmtG(f.stockGramos)}g{bajo&&<span style={{fontSize:11,marginLeft:4}}>⚠</span>}</div>
                      {f.stockGramos===0&&<div style={{fontSize:10,color:"#aa2222",marginTop:2,fontWeight:700}}>AGOTADO</div>}
                      <div className="bar" style={{width:72,marginTop:6,marginLeft:"auto"}}><div className="bar-fill" style={{width:`${pct}%`,background:sc}}/></div>
                    </div>
                  </div>
                  <div style={{display:"flex",justifyContent:"space-between",alignItems:"center",marginTop:4}}>
                    <PosicionBadge posicion={f.posicion} estante={f.estante}/>
                    <div style={{display:"flex",alignItems:"center",gap:8}}>
                      <div style={{fontSize:12,color:"#555",fontWeight:500}}>{fmtARS(f.precioUltimo/f.pesoUnitario*f.stockGramos)}</div>
                      <button onClick={()=>{if(window.confirm(`¿Eliminás ${f.color} ${f.material} (${f.posicion})?`))onDelete(f.key);}} style={{background:"none",border:"1px solid #2a2a2a",cursor:"pointer",color:"#444",fontSize:12,padding:"2px 8px",borderRadius:4,fontFamily:"Montserrat,sans-serif"}} title="Eliminar">× Eliminar</button>
                    </div>
                  </div>
                </div>
              </div>
            );
          })
        }
      </div>
    </div>
  );
}

// ── FORM COMPRA ───────────────────────────────────────────────────────────────
function FormCompra({ maestros, onSubmit }) {
  const empty = {material:"",tipo:"",marca:"",color:"",cantidad:1,pesoUnitario:1000,precio:"",estante:"",posicion:""};
  const [form,setForm] = useState(empty);
  const set=(k,v)=>setForm(f=>({...f,[k]:v}));
  const Sel=({lbl,k,opts})=>(
    <div><div className="lbl">{lbl}</div>
      <select className="inp" value={form[k]} onChange={e=>set(k,e.target.value)}>
        <option value="">— Seleccioná —</option>
        {opts.map(o=><option key={o}>{o}</option>)}
      </select>
    </div>
  );
  const submit=()=>{
    if(!form.material||!form.tipo||!form.marca||!form.color||!form.estante||!form.posicion||!form.precio) return alert("Completá todos los campos.");
    onSubmit({...form,cantidad:Number(form.cantidad),pesoUnitario:Number(form.pesoUnitario),precio:Number(form.precio)});
    setForm(empty);
  };
  return (
    <div style={{maxWidth:580}}>
      <div className="section-title">Registrar compra</div>
      <div className="card" style={{display:"flex",flexDirection:"column",gap:16}}>
        <div className="form-grid" style={{display:"grid",gridTemplateColumns:"1fr 1fr",gap:14}}>
          <Sel lbl="Material"  k="material"  opts={maestros.materiales}/>
          <Sel lbl="Tipo"      k="tipo"       opts={maestros.tipos}/>
          <Sel lbl="Marca"     k="marca"      opts={maestros.marcas}/>
          <Sel lbl="Color"     k="color"      opts={maestros.colores}/>
          <div><div className="lbl">Cantidad de bobinas</div><input className="inp" type="number" min={1} value={form.cantidad} onChange={e=>set("cantidad",e.target.value)}/></div>
          <div><div className="lbl">Peso por bobina (g)</div><input className="inp" type="number" min={1} value={form.pesoUnitario} onChange={e=>set("pesoUnitario",e.target.value)}/></div>
          <div><div className="lbl">Precio total pagado (ARS)</div><input className="inp" type="number" min={0} placeholder="Ej: 15000" value={form.precio} onChange={e=>set("precio",e.target.value)}/></div>
          <Sel lbl="Estante"   k="estante"    opts={maestros.estantes}/>
          <Sel lbl="Posición"  k="posicion"   opts={maestros.posiciones}/>
        </div>
        <div style={{background:"#0d0d0d",borderRadius:8,padding:"10px 14px",fontSize:12,color:"#555",border:"1px solid #1e1e1e"}}>
          Total a incorporar: <span style={{color:"#4b7d0b",fontWeight:700}}>{Number(form.pesoUnitario||0)*Number(form.cantidad||0)}g</span>
          {form.precio&&Number(form.pesoUnitario)>0&&<span style={{marginLeft:16}}>Precio/g: <span style={{color:"#4b7d0b",fontWeight:700}}>{fmtARS(Number(form.precio)/(Number(form.pesoUnitario)*Number(form.cantidad||1)))}</span></span>}
        </div>
        <button className="btn" onClick={submit}>Registrar compra</button>
      </div>
    </div>
  );
}

// ── FORM IMPRESION ────────────────────────────────────────────────────────────
function FormImpresion({ filamentos, onSubmit }) {
  const disponibles = filamentos.filter(f=>f.stockGramos>0);
  const emptyLinea = {key:"",gramos:""};
  const [lineas,setLineas] = useState([{...emptyLinea}]);
  const setLinea=(i,k,v)=>setLineas(ls=>ls.map((l,idx)=>idx===i?{...l,[k]:v}:l));
  const addLinea=()=>setLineas(ls=>[...ls,{...emptyLinea}]);
  const removeLinea=i=>setLineas(ls=>ls.filter((_,idx)=>idx!==i));
  const totalGramos=lineas.reduce((a,l)=>a+(Number(l.gramos)||0),0);
  const submit=()=>{
    const validas=lineas.filter(l=>l.key&&l.gramos&&Number(l.gramos)>0);
    if(validas.length===0) return alert("Agregá al menos un filamento con gramos.");
    for(const l of validas){ const fil=filamentos.find(f=>f.key===l.key); if(Number(l.gramos)>fil.stockGramos) return alert(`Stock insuficiente para ${fil.color}. Disponible: ${fmtG(fil.stockGramos)}g`); }
    onSubmit(validas.map(l=>({key:l.key,gramos:Number(l.gramos)})));
    setLineas([{...emptyLinea}]);
  };
  return (
    <div style={{maxWidth:560}}>
      <div className="section-title">Registrar impresión</div>
      <div className="card" style={{display:"flex",flexDirection:"column",gap:14}}>
        {disponibles.length===0
          ?<div style={{color:"#444",fontSize:13,padding:"8px 0"}}>No hay filamentos con stock disponible.</div>
          :<>
            {lineas.map((linea,i)=>{
              const fil=filamentos.find(f=>f.key===linea.key);
              const restante=fil&&linea.gramos?Math.max(0,fil.stockGramos-Number(linea.gramos)):null;
              // Filtered options for cascading dropdowns
              const coloresDisp=[...new Set(disponibles.map(f=>f.color))].sort();
              const materialesDisp=[...new Set(disponibles.filter(f=>!linea.filtColor||f.color===linea.filtColor).map(f=>f.material))].sort();
              const marcasDisp=[...new Set(disponibles.filter(f=>(!linea.filtColor||f.color===linea.filtColor)&&(!linea.filtMaterial||f.material===linea.filtMaterial)).map(f=>f.marca))].sort();
              const filsFiltrados=disponibles.filter(f=>
                (!linea.filtColor||f.color===linea.filtColor)&&
                (!linea.filtMaterial||f.material===linea.filtMaterial)&&
                (!linea.filtMarca||f.marca===linea.filtMarca)
              );
              return (
                <div key={i} className="imp-row">
                  <div style={{display:"flex",justifyContent:"space-between",alignItems:"center",marginBottom:10}}>
                    <span style={{fontSize:11,color:"#555",fontWeight:700,letterSpacing:".06em"}}>FILAMENTO {i+1}</span>
                    {lineas.length>1&&<button className="btn-sm" onClick={()=>removeLinea(i)}>Quitar</button>}
                  </div>
                  <div style={{display:"grid",gridTemplateColumns:"1fr 1fr",gap:10,marginBottom:10}}>
                    <div>
                      <div className="lbl">Color</div>
                      <select className="inp" value={linea.filtColor||""} onChange={e=>setLinea(i,"filtColor",e.target.value)}>
                        <option value="">— Todos —</option>
                        {coloresDisp.map(c=><option key={c}>{c}</option>)}
                      </select>
                    </div>
                    <div>
                      <div className="lbl">Material</div>
                      <select className="inp" value={linea.filtMaterial||""} onChange={e=>setLinea(i,"filtMaterial",e.target.value)}>
                        <option value="">— Todos —</option>
                        {materialesDisp.map(m=><option key={m}>{m}</option>)}
                      </select>
                    </div>
                    <div>
                      <div className="lbl">Marca</div>
                      <select className="inp" value={linea.filtMarca||""} onChange={e=>setLinea(i,"filtMarca",e.target.value)}>
                        <option value="">— Todas —</option>
                        {marcasDisp.map(m=><option key={m}>{m}</option>)}
                      </select>
                    </div>
                  </div>
                  <div style={{display:"grid",gridTemplateColumns:"1fr 1fr",gap:10}}>
                    <div style={{gridColumn:"1/-1"}}>
                      <div className="lbl">Filamento{filsFiltrados.length>0?` (${filsFiltrados.length} opciones)`:""}</div>
                      <select className="inp" value={linea.key} onChange={e=>setLinea(i,"key",e.target.value)}>
                        <option value="">— Seleccioná —</option>
                        {filsFiltrados.map(f=><option key={f.key} value={f.key}>{f.color} · {f.tipo} · {f.material} · {f.marca} ({fmtG(f.stockGramos)}g){f.posicion?` — ${f.posicion}`:""}</option>)}
                      </select>
                    </div>
                    <div>
                      <div className="lbl">Gramos utilizados</div>
                      <input className="inp" type="number" min={1} placeholder="Ej: 45" value={linea.gramos} onChange={e=>setLinea(i,"gramos",e.target.value)}/>
                    </div>
                    <div style={{display:"flex",flexDirection:"column",justifyContent:"flex-end"}}>
                      {fil&&<div style={{fontSize:11,color:"#555",padding:"11px 14px",background:"#141414",borderRadius:8,border:"1px solid #1e1e1e"}}>
                        Stock: <span style={{color:"#4b7d0b",fontWeight:700}}>{fmtG(fil.stockGramos)}g</span>
                        {fil.posicion&&<span style={{marginLeft:10,color:"#444"}}>📍 {fil.posicion}</span>}
                      </div>}
                    </div>
                  </div>
                  {fil&&linea.gramos&&restante!==null&&(
                    <div style={{marginTop:8,fontSize:11,color:"#555",padding:"8px 12px",background:"#141414",borderRadius:6,border:`1px solid ${restante<STOCK_MINIMO?"#cc444433":"#1e1e1e"}`}}>
                      Restante: <span style={{color:restante<STOCK_MINIMO?"#cc4444":"#4b7d0b",fontWeight:700}}>{fmtG(restante)}g</span>
                      {restante<STOCK_MINIMO&&<span style={{color:"#cc4444",marginLeft:8,fontSize:10}}>⚠ quedará bajo stock</span>}
                    </div>
                  )}
                </div>
              );
            })}
            <button className="btn-add" style={{alignSelf:"flex-start"}} onClick={addLinea}>+ Agregar otro filamento</button>
            {lineas.length>1&&totalGramos>0&&(
              <div style={{fontSize:12,color:"#555",padding:"10px 14px",background:"#0d0d0d",borderRadius:8,border:"1px solid #1e1e1e"}}>
                Total impresión: <span style={{color:"#4b7d0b",fontWeight:700}}>{fmtG(totalGramos)}g</span>
              </div>
            )}
            <button className="btn" onClick={submit}>Registrar impresión</button>
          </>
        }
      </div>

    </div>
  );
}

// ── HISTORIAL ─────────────────────────────────────────────────────────────────
function Historial({ movimientos }) {
  const sorted=[...movimientos].sort((a,b)=>new Date(b.fecha)-new Date(a.fecha));
  const rows=[]; const seen=new Set();
  sorted.forEach(m=>{
    if(m.tipo==="ajuste"){rows.push({type:"ajuste",data:m});return;}
    if(m.tipo==="compra"){rows.push({type:"compra",data:m});return;}
    if(m.grupoId){ if(seen.has(m.grupoId))return; seen.add(m.grupoId); const grupo=sorted.filter(x=>x.grupoId===m.grupoId); rows.push({type:"impresion_grupo",data:grupo,fecha:m.fecha,id:m.grupoId}); }
    else { rows.push({type:"impresion",data:m}); }
  });
  return (
    <div>
      <div className="section-title">Historial de movimientos</div>
      <div className="card">
        {rows.length===0
          ?<div style={{color:"#333",fontSize:13,textAlign:"center",padding:"20px 0"}}>Sin movimientos registrados.</div>
          :rows.map((row,ri)=>{
            if(row.type==="ajuste"){const m=row.data;return(
              <div key={m.id} style={{display:"flex",justifyContent:"space-between",alignItems:"center",padding:"12px 0",borderBottom:"1px solid #1a1a1a"}}>
                <div style={{display:"flex",alignItems:"center",gap:12,flexWrap:"wrap"}}>
                  <span style={{fontSize:9,padding:"3px 8px",borderRadius:4,letterSpacing:".06em",fontWeight:700,background:"#1a1a3a",color:"#6688cc",border:"1px solid #2a2a5a"}}>AJUSTE</span>
                  <div><span style={{fontSize:13,color:"#ccc",fontWeight:500}}>{m.color} {m.material}</span><span style={{fontSize:11,color:"#444",marginLeft:8}}>{m.marca}</span></div>
                </div>
                <div style={{textAlign:"right",flexShrink:0,marginLeft:12}}>
                  <div style={{fontSize:13,fontWeight:700,color:"#6688cc"}}>{fmtG(m.gramos)}g</div>
                  <div style={{fontSize:10,color:"#333",marginTop:2}}>{new Date(m.fecha).toLocaleDateString("es-AR",{day:"2-digit",month:"short",year:"numeric"})}</div>
                </div>
              </div>
            );}
    if(row.type==="compra"){const m=row.data;return(
              <div key={m.id} style={{display:"flex",justifyContent:"space-between",alignItems:"center",padding:"12px 0",borderBottom:"1px solid #1a1a1a"}}>
                <div style={{display:"flex",alignItems:"center",gap:12,flexWrap:"wrap"}}>
                  <span style={{fontSize:9,padding:"3px 8px",borderRadius:4,letterSpacing:".06em",fontWeight:700,background:"#4b7d0b18",color:"#4b7d0b",border:"1px solid #4b7d0b33"}}>COMPRA</span>
                  <div><span style={{fontSize:13,color:"#ffffff",fontWeight:500}}>{m.color} {m.material}</span><span style={{fontSize:11,color:"#444",marginLeft:8}}>{m.tipo_fil}</span><span style={{fontSize:11,color:"#333",marginLeft:8}}>{m.marca}</span><span style={{fontSize:10,color:"#444",marginLeft:8}}>{m.cantidad} bobina{m.cantidad>1?"s":""}</span></div>
                </div>
                <div style={{textAlign:"right",flexShrink:0,marginLeft:12}}>
                  <div style={{fontSize:13,fontWeight:700,color:"#4b7d0b"}}>+{fmtG(m.gramos)}g</div>
                  <div style={{fontSize:10,color:"#333",marginTop:2}}>{new Date(m.fecha).toLocaleDateString("es-AR",{day:"2-digit",month:"short",year:"numeric"})}</div>
                </div>
              </div>
            );}
            if(row.type==="impresion_grupo"){const grupo=row.data;const total=grupo.reduce((a,x)=>a+x.gramos,0);return(
              <div key={row.id} style={{padding:"12px 0",borderBottom:"1px solid #1a1a1a"}}>
                <div style={{display:"flex",justifyContent:"space-between",alignItems:"flex-start"}}>
                  <div style={{display:"flex",alignItems:"center",gap:12}}><span style={{fontSize:9,padding:"3px 8px",borderRadius:4,letterSpacing:".06em",fontWeight:700,background:"#ffffff08",color:"#777",border:"1px solid #252525"}}>IMPRESIÓN</span><span style={{fontSize:11,color:"#555",fontWeight:500}}>{grupo.length} filamento{grupo.length>1?"s":""}</span></div>
                  <div style={{textAlign:"right",flexShrink:0,marginLeft:12}}>
                    <div style={{fontSize:13,fontWeight:700,color:"#cc5555"}}>-{fmtG(total)}g</div>
                    <div style={{fontSize:10,color:"#333",marginTop:2}}>{new Date(row.fecha).toLocaleDateString("es-AR",{day:"2-digit",month:"short",year:"numeric"})}</div>
                  </div>
                </div>
                <div style={{marginTop:6,paddingLeft:8,borderLeft:"2px solid #252525",marginLeft:4}}>
                  {grupo.map(x=>(<div key={x.id} style={{fontSize:11,color:"#555",padding:"2px 0"}}><span style={{color:"#aaa",fontWeight:500}}>{x.color} {x.material}</span><span style={{color:"#cc5555",marginLeft:8,fontWeight:600}}>-{fmtG(x.gramos)}g</span><span style={{color:"#333",marginLeft:8}}>{x.marca}</span></div>))}
                </div>
              </div>
            );}
            const m=row.data;return(
              <div key={m.id} style={{display:"flex",justifyContent:"space-between",alignItems:"center",padding:"12px 0",borderBottom:"1px solid #1a1a1a"}}>
                <div style={{display:"flex",alignItems:"center",gap:12}}><span style={{fontSize:9,padding:"3px 8px",borderRadius:4,letterSpacing:".06em",fontWeight:700,background:"#ffffff08",color:"#777",border:"1px solid #252525"}}>IMPRESIÓN</span><div><span style={{fontSize:13,color:"#ffffff",fontWeight:500}}>{m.color} {m.material}</span></div></div>
                <div style={{textAlign:"right",flexShrink:0,marginLeft:12}}><div style={{fontSize:13,fontWeight:700,color:"#cc5555"}}>-{fmtG(m.gramos)}g</div><div style={{fontSize:10,color:"#333",marginTop:2}}>{new Date(m.fecha).toLocaleDateString("es-AR",{day:"2-digit",month:"short",year:"numeric"})}</div></div>
              </div>
            );
          })
        }
      </div>
    </div>
  );
}

// ── STOCK TABLA (shared) ──────────────────────────────────────────────────────
function StockTabla({ filamentos, onDelete }) {
  const [sortCol,setSortCol] = useState("color");
  const [sortDir,setSortDir] = useState("asc");
  const [searchColor,setSearchColor]     = useState("");
  const [searchMarca,setSearchMarca]     = useState("");
  const [searchMaterial,setSearchMaterial] = useState("");
  const [showSug,setShowSug]             = useState(false);

  const allColors = [...new Set(filamentos.map(f=>f.color))].sort();
  const suggestions = searchColor.length > 0 ? allColors.filter(c=>c.toLowerCase().includes(searchColor.toLowerCase())) : [];

  const filtered = filamentos.filter(f=>{
    const mc = !searchColor    || f.color.toLowerCase().includes(searchColor.toLowerCase());
    const mm = !searchMarca    || f.marca.toLowerCase().includes(searchMarca.toLowerCase());
    const mt = !searchMaterial || f.material.toLowerCase().includes(searchMaterial.toLowerCase());
    return mc && mm && mt;
  });

  const sorted = [...filtered].sort((a,b)=>{
    let va=a[sortCol], vb=b[sortCol];
    if(sortCol==="stockGramos"||sortCol==="precioUltimo"){ va=Number(va); vb=Number(vb); }
    else { va=String(va).toLowerCase(); vb=String(vb).toLowerCase(); }
    if(va<vb) return sortDir==="asc"?-1:1;
    if(va>vb) return sortDir==="asc"?1:-1;
    return 0;
  });

  const toggleSort = col => {
    if(sortCol===col) setSortDir(d=>d==="asc"?"desc":"asc");
    else { setSortCol(col); setSortDir("asc"); }
  };
  const SortArrow = ({col}) => sortCol!==col
    ? <span style={{color:"#2a2a2a",marginLeft:3}}>↕</span>
    : <span style={{color:"#4b7d0b",marginLeft:3}}>{sortDir==="asc"?"↑":"↓"}</span>;
  const TH = ({col,label,style={}}) => (
    <div className="sort-th" style={{fontSize:9,color:"#444",letterSpacing:".08em",textTransform:"uppercase",fontWeight:600,...style}} onClick={()=>toggleSort(col)}>
      {label}<SortArrow col={col}/>
    </div>
  );
  const cols = "1.4fr 0.7fr 0.7fr 0.8fr 1fr 1.6fr 0.7fr 28px";

  return (
    <div className="card" style={{marginTop:20}}>
      <div style={{fontSize:12,color:"#aaa",fontWeight:700,marginBottom:14,letterSpacing:".04em",textTransform:"uppercase"}}>Detalle de stock</div>
      {/* Filters */}
      <div style={{display:"grid",gridTemplateColumns:"1fr 1fr 1fr",gap:10,marginBottom:16}}>
        <div style={{position:"relative"}}>
          <div className="lbl">Buscar por color</div>
          <input className="inp" style={{padding:"8px 12px",fontSize:12}} placeholder="Ej: Negro..." value={searchColor}
            onChange={e=>{setSearchColor(e.target.value);setShowSug(true);}}
            onFocus={()=>setShowSug(true)} onBlur={()=>setTimeout(()=>setShowSug(false),150)}/>
          {showSug&&suggestions.length>0&&(
            <div style={{position:"absolute",top:"100%",left:0,right:0,background:"#141414",border:"1px solid #252525",borderRadius:8,zIndex:100,maxHeight:160,overflowY:"auto",marginTop:2}}>
              {suggestions.map(s=><div key={s} className="search-suggestion" onMouseDown={()=>{setSearchColor(s);setShowSug(false);}}>{s}</div>)}
            </div>
          )}
        </div>
        <div>
          <div className="lbl">Filtrar por marca</div>
          <input className="inp" style={{padding:"8px 12px",fontSize:12}} placeholder="Ej: Grilon3..." value={searchMarca} onChange={e=>setSearchMarca(e.target.value)}/>
        </div>
        <div>
          <div className="lbl">Filtrar por material</div>
          <input className="inp" style={{padding:"8px 12px",fontSize:12}} placeholder="Ej: PLA..." value={searchMaterial} onChange={e=>setSearchMaterial(e.target.value)}/>
        </div>
      </div>
      {(searchColor||searchMarca||searchMaterial)&&(
        <div style={{marginBottom:12,display:"flex",alignItems:"center",gap:8}}>
          <span style={{fontSize:11,color:"#555"}}>{sorted.length} resultado{sorted.length!==1?"s":""}</span>
          <button onClick={()=>{setSearchColor("");setSearchMarca("");setSearchMaterial("");}} style={{fontSize:10,background:"none",border:"1px solid #333",borderRadius:4,padding:"2px 8px",color:"#666",cursor:"pointer",fontFamily:"Montserrat,sans-serif"}}>Limpiar filtros</button>
        </div>
      )}
      {/* Header */}
      <div className="desktop-row" style={{display:"grid",gridTemplateColumns:cols,gap:10,padding:"0 0 10px",borderBottom:"1px solid #1e1e1e",marginBottom:2}}>
        <TH col="color" label="Color"/><TH col="material" label="Material"/><TH col="tipo" label="Tipo"/>
        <TH col="marca" label="Marca"/><TH col="stockGramos" label="Stock"/>
        <div style={{fontSize:9,color:"#555",letterSpacing:".08em",textTransform:"uppercase",fontWeight:600}}>Ubicación</div>
        <TH col="precioUltimo" label="Valor" style={{textAlign:"right"}}/><div/>
      </div>
      {sorted.length===0
        ?<div style={{color:"#333",fontSize:13,textAlign:"center",padding:"16px 0"}}>Sin resultados.</div>
        :sorted.map(f=>{
          const pct=Math.min(100,(f.stockGramos/f.pesoUnitario)*100);
          const bajo=f.stockGramos>0&&f.stockGramos<STOCK_MINIMO;
          const sc=bajo?"#cc4444":f.stockGramos===0?"#aa2222":"#4b7d0b";
          return (
            <div key={f.key}>
              <div className="desktop-row" style={{display:"grid",gridTemplateColumns:cols,gap:10,alignItems:"center",borderBottom:"1px solid #1a1a1a",padding:"11px 0"}}>
                <div style={{fontSize:13,color:"#e0e0e0",fontWeight:600}}>{f.color}</div>
                <div style={{fontSize:11,color:"#666",fontWeight:500}}>{f.material}</div>
                <div style={{fontSize:10,color:"#444",fontWeight:500}}>{f.tipo}</div>
                <div style={{fontSize:11,color:"#666",fontWeight:500}}>{f.marca}</div>
                <div>
                  <div style={{fontSize:13,color:sc,fontWeight:700}}>{fmtG(f.stockGramos)}g{bajo&&<span style={{fontSize:9,marginLeft:4}}>⚠</span>}{f.stockGramos===0&&<span style={{fontSize:9,marginLeft:4}}>AGOTADO</span>}</div>
                  <div className="bar"><div className="bar-fill" style={{width:`${pct}%`,background:sc}}/></div>
                </div>
                <PosicionBadge posicion={f.posicion} estante={f.estante}/>
                <div style={{fontSize:11,color:"#444",textAlign:"right",fontWeight:500}}>{fmtARS(f.precioUltimo/f.pesoUnitario*f.stockGramos)}</div>
                <button onClick={()=>{if(window.confirm(`¿Eliminás ${f.color} ${f.material} (${f.posicion})?`))onDelete(f.key);}} style={{background:"none",border:"none",cursor:"pointer",color:"#333",fontSize:14,padding:"2px 4px",borderRadius:4,transition:"color .2s"}} onMouseEnter={e=>e.target.style.color="#cc4444"} onMouseLeave={e=>e.target.style.color="#333"} title="Eliminar">×</button>
              </div>
              <div className="mobile-card" style={{borderBottom:"1px solid #1a1a1a",padding:"14px 0"}}>
                <div style={{display:"flex",justifyContent:"space-between",alignItems:"flex-start",marginBottom:10}}>
                  <div style={{flex:1}}>
                    <div style={{fontSize:16,color:"#e0e0e0",fontWeight:700,marginBottom:6}}>{f.color}</div>
                    <div style={{display:"flex",gap:5,flexWrap:"wrap"}}>
                      <span style={{fontSize:10,color:"#888",background:"#1a1a1a",border:"1px solid #252525",borderRadius:4,padding:"2px 8px",fontWeight:600}}>{f.material}</span>
                      <span style={{fontSize:10,color:"#666",background:"#1a1a1a",border:"1px solid #252525",borderRadius:4,padding:"2px 8px"}}>{f.tipo}</span>
                      <span style={{fontSize:10,color:"#555",background:"#1a1a1a",border:"1px solid #252525",borderRadius:4,padding:"2px 8px"}}>{f.marca}</span>
                    </div>
                  </div>
                  <div style={{textAlign:"right",flexShrink:0,marginLeft:16}}>
                    <div style={{fontSize:18,color:sc,fontWeight:800,lineHeight:1}}>{fmtG(f.stockGramos)}g{bajo&&<span style={{fontSize:11,marginLeft:4}}>⚠</span>}</div>
                    {f.stockGramos===0&&<div style={{fontSize:10,color:"#aa2222",marginTop:2,fontWeight:700}}>AGOTADO</div>}
                    <div className="bar" style={{width:72,marginTop:6,marginLeft:"auto"}}><div className="bar-fill" style={{width:`${pct}%`,background:sc}}/></div>
                  </div>
                </div>
                <div style={{display:"flex",justifyContent:"space-between",alignItems:"center",marginTop:4}}>
                  <PosicionBadge posicion={f.posicion} estante={f.estante}/>
                  <div style={{display:"flex",alignItems:"center",gap:8}}>
                    <div style={{fontSize:12,color:"#555",fontWeight:500}}>{fmtARS(f.precioUltimo/f.pesoUnitario*f.stockGramos)}</div>
                    <button onClick={()=>{if(window.confirm(`¿Eliminás ${f.color} ${f.material}?`))onDelete(f.key);}} style={{background:"none",border:"1px solid #2a2a2a",cursor:"pointer",color:"#444",fontSize:12,padding:"2px 8px",borderRadius:4,fontFamily:"Montserrat,sans-serif"}}>× Eliminar</button>
                  </div>
                </div>
              </div>
            </div>
          );
        })
      }
    </div>
  );
}


// ── AJUSTE STOCK ──────────────────────────────────────────────────────────────
function AjusteStock({ filamentos, maestros, onAjuste, onDelete }) {
  const [selectedKey, setSelectedKey] = useState("");
  const [pesoBrutoCargado, setPesoBrutoCargado] = useState("");
  const [marcaBobina, setMarcaBobina] = useState("");
  const [confirmado, setConfirmado] = useState(false);
  const [filtColor, setFiltColor]       = useState("");
  const [filtMaterial, setFiltMaterial] = useState("");
  const [filtTipo, setFiltTipo]         = useState("");
  const [filtMarca, setFiltMarca]       = useState("");

  const bobinas = maestros.bobinas || [];
  const fil = filamentos.find(f => f.key === selectedKey);
  const pesoBobin = bobinas.find(b => b.marca === marcaBobina)?.pesoBobina || 0;
  const stockNeto = pesoBrutoCargado && pesoBobin ? Math.max(0, Number(pesoBrutoCargado) - pesoBobin) : null;
  const diferencia = fil && stockNeto !== null ? stockNeto - fil.stockGramos : null;

  const reset = () => { setSelectedKey(""); setPesoBrutoCargado(""); setMarcaBobina(""); setConfirmado(false); setFiltColor(""); setFiltMaterial(""); setFiltTipo(""); setFiltMarca(""); };

  const submit = () => {
    if (!selectedKey || stockNeto === null) return alert("Completá todos los campos.");
    if (stockNeto < 0) return alert("El peso neto no puede ser negativo.");
    onAjuste(selectedKey, stockNeto);
    reset();
  };

  return (
    <div style={{maxWidth:1400}}>
      <div className="section-title">Ajuste de stock</div>
      <div style={{display:"grid",gridTemplateColumns:"500px 1fr",gap:20,alignItems:"start"}} className="ajuste-grid">
      <div>
      <div style={{fontSize:12,color:"#555",marginBottom:20,lineHeight:1.6}}>
        Usá esta sección para corregir el stock de una bobina pesándola en ese momento. Ingresá el peso bruto (bobina + filamento) y el sistema descuenta el peso de la bobina vacía automáticamente.
      </div>
      <div className="card" style={{display:"flex",flexDirection:"column",gap:16}}>
        {/* Cascading filters */}
        <div style={{display:"grid",gridTemplateColumns:"1fr 1fr",gap:12}}>
          <div>
            <div className="lbl">Filtrar por color</div>
            <select className="inp" value={filtColor} onChange={e=>{setFiltColor(e.target.value);setSelectedKey("");setConfirmado(false);}}>
              <option value="">— Todos —</option>
              {[...new Set(filamentos.map(f=>f.color))].sort().map(c=><option key={c}>{c}</option>)}
            </select>
          </div>
          <div>
            <div className="lbl">Filtrar por material</div>
            <select className="inp" value={filtMaterial} onChange={e=>{setFiltMaterial(e.target.value);setSelectedKey("");setConfirmado(false);}}>
              <option value="">— Todos —</option>
              {[...new Set(filamentos.filter(f=>!filtColor||f.color===filtColor).map(f=>f.material))].sort().map(m=><option key={m}>{m}</option>)}
            </select>
          </div>
          <div>
            <div className="lbl">Filtrar por tipo</div>
            <select className="inp" value={filtTipo} onChange={e=>{setFiltTipo(e.target.value);setSelectedKey("");setConfirmado(false);}}>
              <option value="">— Todos —</option>
              {[...new Set(filamentos.filter(f=>(!filtColor||f.color===filtColor)&&(!filtMaterial||f.material===filtMaterial)).map(f=>f.tipo))].sort().map(t=><option key={t}>{t}</option>)}
            </select>
          </div>
          <div>
            <div className="lbl">Filtrar por marca</div>
            <select className="inp" value={filtMarca} onChange={e=>{setFiltMarca(e.target.value);setSelectedKey("");setConfirmado(false);}}>
              <option value="">— Todas —</option>
              {[...new Set(filamentos.filter(f=>(!filtColor||f.color===filtColor)&&(!filtMaterial||f.material===filtMaterial)&&(!filtTipo||f.tipo===filtTipo)).map(f=>f.marca))].sort().map(m=><option key={m}>{m}</option>)}
            </select>
          </div>
        </div>
        <div>
          <div className="lbl">Seleccionar rollo específico</div>
          <select className="inp" value={selectedKey} onChange={e=>{setSelectedKey(e.target.value);setConfirmado(false);}}>
            <option value="">— Seleccioná un rollo —</option>
            {filamentos.filter(f=>
              (!filtColor||f.color===filtColor)&&
              (!filtMaterial||f.material===filtMaterial)&&
              (!filtTipo||f.tipo===filtTipo)&&
              (!filtMarca||f.marca===filtMarca)
            ).map(f=>(
              <option key={f.key} value={f.key}>
                {f.color} · {f.tipo} · {f.material} · {f.marca}{f.estante?` — ${f.estante.replace("Estante ","")}`:""}{f.posicion?` ${f.posicion}`:""} — {fmtG(f.stockGramos)}g
              </option>
            ))}
          </select>
        </div>

        {fil && (
          <div style={{background:"#0d0d0d",borderRadius:8,padding:"10px 14px",fontSize:12,color:"#555",border:"1px solid #1e1e1e",display:"flex",gap:16,flexWrap:"wrap"}}>
            <span>Stock actual: <span style={{color:"#4b7d0b",fontWeight:700}}>{fmtG(fil.stockGramos)}g</span></span>
            {fil.posicion && <span>Ubicación: <span style={{color:"#888"}}>{fil.estante} — {fil.posicion}</span></span>}
          </div>
        )}

        <div>
          <div className="lbl">Marca de la bobina vacía</div>
          <select className="inp" value={marcaBobina} onChange={e=>setMarcaBobina(e.target.value)}>
            <option value="">— Seleccioná marca de bobina —</option>
            {bobinas.map(b=>(
              <option key={b.marca} value={b.marca}>{b.marca} ({fmtG(b.pesoBobina)}g)</option>
            ))}
          </select>
        </div>

        <div>
          <div className="lbl">Peso bruto total (bobina + filamento, en gramos)</div>
          <input className="inp" type="number" min={0} placeholder="Ej: 450" value={pesoBrutoCargado} onChange={e=>{setPesoBrutoCargado(e.target.value);setConfirmado(false);}}/>
        </div>

        {stockNeto !== null && marcaBobina && (
          <div style={{background:"#0d0d0d",borderRadius:10,padding:"14px 16px",border:"1px solid #252525"}}>
            <div style={{fontSize:11,color:"#555",marginBottom:8,fontWeight:600,letterSpacing:".06em",textTransform:"uppercase"}}>Resumen del ajuste</div>
            <div style={{display:"grid",gridTemplateColumns:"1fr 1fr 1fr",gap:10}}>
              <div>
                <div style={{fontSize:10,color:"#444",marginBottom:3}}>Peso bruto</div>
                <div style={{fontSize:15,color:"#aaa",fontWeight:700}}>{fmtG(Number(pesoBrutoCargado))}g</div>
              </div>
              <div>
                <div style={{fontSize:10,color:"#444",marginBottom:3}}>Bobina vacía</div>
                <div style={{fontSize:15,color:"#cc5555",fontWeight:700}}>−{fmtG(pesoBobin)}g</div>
              </div>
              <div>
                <div style={{fontSize:10,color:"#444",marginBottom:3}}>Stock neto</div>
                <div style={{fontSize:15,color:"#4b7d0b",fontWeight:700}}>{fmtG(stockNeto)}g</div>
              </div>
            </div>
            {fil && diferencia !== null && (
              <div style={{marginTop:12,paddingTop:12,borderTop:"1px solid #1a1a1a",fontSize:12,color:"#555"}}>
                Cambio respecto al stock actual:
                <span style={{marginLeft:8,fontWeight:700,color:diferencia>=0?"#4b7d0b":"#cc5555"}}>
                  {diferencia>=0?"+":""}{fmtG(diferencia)}g
                </span>
                {diferencia<0&&<span style={{marginLeft:8,fontSize:10,color:"#cc5555"}}>({fmtG(Math.abs(diferencia))}g de consumo no registrado)</span>}
              </div>
            )}
            <div style={{marginTop:14}}>
              <label style={{display:"flex",alignItems:"center",gap:8,cursor:"pointer",fontSize:12,color:"#666"}}>
                <input type="checkbox" checked={confirmado} onChange={e=>setConfirmado(e.target.checked)} style={{width:14,height:14,accentColor:"#4b7d0b"}}/>
                Confirmo que el nuevo stock es <strong style={{color:"#e0e0e0",marginLeft:4}}>{fmtG(stockNeto)}g</strong>
              </label>
            </div>
          </div>
        )}

        <button className="btn" onClick={submit} style={{opacity:(!confirmado||!selectedKey||stockNeto===null)?0.4:1,cursor:(!confirmado||!selectedKey||stockNeto===null)?"not-allowed":"pointer"}}>
          Aplicar ajuste de stock
        </button>
      </div>

      </div>
      <StockTabla filamentos={filamentos} onDelete={onDelete}/>
      </div>
    </div>
  );
}


// ── CALCULADORA DE COSTO ──────────────────────────────────────────────────────
function Calculadora({ filamentos }) {
  // Gastos fijos de la máquina (persistidos)
  const [cfg, setCfg] = useState(() => {
    try { const v = localStorage.getItem("lenga_calc_cfg"); return v ? JSON.parse(v) : null; } catch { return null; }
  });
  const defaultCfg = { precioKwh:140, consumoW:120, hsMaquina:4320, precioRepuestos:150000, margenError:10 };
  const [gastos, setGastos] = useState(cfg || defaultCfg);
  const [showGastos, setShowGastos] = useState(false);

  // Lineas de filamento
  const emptyLinea = { key:"", gramos:"" };
  const [lineas, setLineas] = useState([{...emptyLinea}]);
  const setLinea = (i,k,v) => setLineas(ls => ls.map((l,idx) => idx===i ? {...l,[k]:v} : l));

  // Pieza
  const [horas, setHoras] = useState("");
  const [minutos, setMinutos] = useState("");
  const [insumos, setInsumos] = useState("");
  const [multiplicador, setMultiplicador] = useState(5);
  const [resultado, setResultado] = useState(null);

  const saveGastos = g => { setGastos(g); try { localStorage.setItem("lenga_calc_cfg", JSON.stringify(g)); } catch {} };
  const setG = (k,v) => saveGastos({...gastos,[k]:v});

  const disponibles = filamentos.filter(f => f.stockGramos > 0);

  const calcular = () => {
    const tiempoH = (Number(horas)||0) + (Number(minutos)||0)/60;
    const lineasValidas = lineas.filter(l => l.key && l.gramos && Number(l.gramos) > 0);
    if (lineasValidas.length === 0) { alert("Agregá al menos un filamento con gramos."); return; }

    // Costo material
    const costoMaterial = lineasValidas.reduce((a, l) => {
      const fil = filamentos.find(f => f.key === l.key);
      return a + (fil ? (fil.precioUltimo / fil.pesoUnitario) * Number(l.gramos) : 0);
    }, 0);
    const totalGramos = lineasValidas.reduce((a,l) => a + Number(l.gramos), 0);

    // Costo luz
    const costoLuz = tiempoH > 0 ? (gastos.consumoW / 1000) * tiempoH * gastos.precioKwh : 0;

    // Desgaste máquina (precio repuestos / horas de vida)
    const costoMaquina = tiempoH > 0 && gastos.hsMaquina > 0
      ? (gastos.precioRepuestos / gastos.hsMaquina) * tiempoH : 0;

    // Margen de error sobre material
    // margenErrorARS calculated below after costoMaquina

    // Insumos extra
    const costoInsumos = Number(insumos) || 0;

    const margenBase = costoMaterial + costoLuz + costoMaquina;
    const margenErrorARS_recalc = margenBase * (gastos.margenError / 100);
    const subtotal = costoMaterial + costoLuz + costoMaquina + margenErrorARS_recalc + costoInsumos;
    const totalVenta = subtotal * multiplicador;
    const totalML = totalVenta * 1.8; // MercadoLibre: +80% sobre precio de venta

    setResultado({ costoMaterial, costoLuz, costoMaquina, margenErrorARS:margenErrorARS_recalc, costoInsumos, subtotal, totalVenta, totalML, totalGramos, tiempoH });
  };

  const InputNum = ({label, val, onChange, placeholder, suffix}) => (
    <div>
      <div className="lbl">{label}{suffix && <span style={{color:"#444",marginLeft:4,fontSize:9}}>{suffix}</span>}</div>
      <input className="inp" type="number" min={0} placeholder={placeholder||"0"} value={val} onChange={e=>onChange(e.target.value)}/>
    </div>
  );

  return (
    <div style={{maxWidth:640}}>
      <div className="section-title">Calculadora de costo</div>

      {/* Config gastos fijos */}
      <div className="card" style={{marginBottom:14}}>
        <button onClick={()=>setShowGastos(v=>!v)} style={{display:"flex",justifyContent:"space-between",alignItems:"center",width:"100%",background:"none",border:"none",cursor:"pointer",padding:0}}>
          <div style={{fontSize:12,color:"#aaa",fontWeight:700,letterSpacing:".06em",textTransform:"uppercase"}}>⚙ Gastos fijos de la máquina</div>
          <span style={{fontSize:10,color:"#555"}}>{showGastos?"▲ Ocultar":"▼ Editar"}</span>
        </button>
        {showGastos && (
          <div style={{marginTop:16,display:"grid",gridTemplateColumns:"1fr 1fr",gap:12}} className="form-grid">
            <InputNum label="Precio kWh" suffix="ARS" val={gastos.precioKwh} onChange={v=>setG("precioKwh",Number(v))} placeholder="140"/>
            <InputNum label="Consumo real impresora" suffix="W" val={gastos.consumoW} onChange={v=>setG("consumoW",Number(v))} placeholder="120"/>
            <InputNum label="Vida útil máquina" suffix="horas" val={gastos.hsMaquina} onChange={v=>setG("hsMaquina",Number(v))} placeholder="4320"/>
            <InputNum label="Precio repuestos estimados" suffix="ARS" val={gastos.precioRepuestos} onChange={v=>setG("precioRepuestos",Number(v))} placeholder="150000"/>
            <InputNum label="Margen de error material" suffix="%" val={gastos.margenError} onChange={v=>setG("margenError",Number(v))} placeholder="10"/>
          </div>
        )}
        {!showGastos && (
          <div style={{marginTop:10,display:"flex",gap:16,flexWrap:"wrap"}}>
            {[["kWh",`${fmtARS(gastos.precioKwh)}`],["Consumo",`${gastos.consumoW}W`],["Vida máq.",`${gastos.hsMaquina}hs`],["Error mat.",`${gastos.margenError}%`]].map(([k,v])=>(
              <div key={k} style={{fontSize:11,color:"#444"}}>{k}: <span style={{color:"#666",fontWeight:600}}>{v}</span></div>
            ))}
          </div>
        )}
      </div>

      {/* Filamentos */}
      <div className="card" style={{marginBottom:14}}>
        <div style={{fontSize:12,color:"#aaa",fontWeight:700,marginBottom:14,letterSpacing:".06em",textTransform:"uppercase"}}>Filamentos de la pieza</div>
        {lineas.map((linea,i) => {
          const fil = filamentos.find(f => f.key===linea.key);
          const costoParcial = fil && linea.gramos ? (fil.precioUltimo/fil.pesoUnitario)*Number(linea.gramos) : null;
          const coloresDisp=[...new Set(disponibles.map(f=>f.color))].sort();
          const materialesDisp=[...new Set(disponibles.filter(f=>!linea.filtColor||f.color===linea.filtColor).map(f=>f.material))].sort();
          const marcasDisp=[...new Set(disponibles.filter(f=>(!linea.filtColor||f.color===linea.filtColor)&&(!linea.filtMaterial||f.material===linea.filtMaterial)).map(f=>f.marca))].sort();
          const filsFiltrados=disponibles.filter(f=>
            (!linea.filtColor||f.color===linea.filtColor)&&
            (!linea.filtMaterial||f.material===linea.filtMaterial)&&
            (!linea.filtMarca||f.marca===linea.filtMarca)
          );
          return (
            <div key={i} className="imp-row">
              <div style={{display:"flex",justifyContent:"space-between",alignItems:"center",marginBottom:10}}>
                <span style={{fontSize:11,color:"#555",fontWeight:700,letterSpacing:".06em"}}>FILAMENTO {i+1}</span>
                {lineas.length>1 && <button className="btn-sm" onClick={()=>setLineas(ls=>ls.filter((_,idx)=>idx!==i))}>Quitar</button>}
              </div>
              <div style={{display:"grid",gridTemplateColumns:"1fr 1fr",gap:10,marginBottom:10}}>
                <div>
                  <div className="lbl">Color</div>
                  <select className="inp" value={linea.filtColor||""} onChange={e=>setLinea(i,"filtColor",e.target.value)}>
                    <option value="">— Todos —</option>
                    {coloresDisp.map(c=><option key={c}>{c}</option>)}
                  </select>
                </div>
                <div>
                  <div className="lbl">Material</div>
                  <select className="inp" value={linea.filtMaterial||""} onChange={e=>setLinea(i,"filtMaterial",e.target.value)}>
                    <option value="">— Todos —</option>
                    {materialesDisp.map(m=><option key={m}>{m}</option>)}
                  </select>
                </div>
                <div>
                  <div className="lbl">Marca</div>
                  <select className="inp" value={linea.filtMarca||""} onChange={e=>setLinea(i,"filtMarca",e.target.value)}>
                    <option value="">— Todas —</option>
                    {marcasDisp.map(m=><option key={m}>{m}</option>)}
                  </select>
                </div>
              </div>
              <div style={{display:"grid",gridTemplateColumns:"1fr 1fr",gap:10}}>
                <div style={{gridColumn:"1/-1"}}>
                  <div className="lbl">Filamento{filsFiltrados.length>0?` (${filsFiltrados.length} opciones)`:""}</div>
                  <select className="inp" value={linea.key} onChange={e=>setLinea(i,"key",e.target.value)}>
                    <option value="">— Seleccioná —</option>
                    {filsFiltrados.map(f=><option key={f.key} value={f.key}>{f.color} · {f.tipo} · {f.material} · {f.marca} ({fmtG(f.stockGramos)}g)</option>)}
                  </select>
                </div>
                <div>
                  <div className="lbl">Gramos</div>
                  <input className="inp" type="number" min={1} placeholder="Ej: 45" value={linea.gramos} onChange={e=>setLinea(i,"gramos",e.target.value)}/>
                </div>
                <div style={{display:"flex",alignItems:"flex-end"}}>
                  {fil && linea.gramos && costoParcial !== null && (
                    <div style={{background:"#0d0d0d",borderRadius:8,padding:"11px 14px",fontSize:12,border:"1px solid #1e1e1e",width:"100%"}}>
                      Costo: <span style={{color:"#4b7d0b",fontWeight:700}}>{fmtARS(costoParcial)}</span>
                      <span style={{color:"#333",marginLeft:8,fontSize:10}}>{fmtARS(fil.precioUltimo/fil.pesoUnitario)}/g</span>
                    </div>
                  )}
                </div>
              </div>
            </div>
          );
        })}
        <button className="btn-add" style={{alignSelf:"flex-start",marginTop:4}} onClick={()=>setLineas(ls=>[...ls,{...emptyLinea}])}>+ Agregar filamento</button>
      </div>

      {/* Tiempo e insumos */}
      <div className="card" style={{marginBottom:14}}>
        <div style={{fontSize:12,color:"#aaa",fontWeight:700,marginBottom:14,letterSpacing:".06em",textTransform:"uppercase"}}>Tiempo e insumos adicionales</div>
        <div style={{display:"grid",gridTemplateColumns:"1fr 1fr 1fr",gap:12}} className="form-grid">
          <InputNum label="Horas de impresión" suffix="hs" val={horas} onChange={setHoras} placeholder="0"/>
          <InputNum label="Minutos" suffix="min" val={minutos} onChange={setMinutos} placeholder="0"/>
          <InputNum label="Insumos extra" suffix="ARS" val={insumos} onChange={setInsumos} placeholder="Ej: 500"/>
        </div>
      </div>

      {/* Multiplicador */}
      <div className="card" style={{marginBottom:14}}>
        <div style={{fontSize:12,color:"#aaa",fontWeight:700,marginBottom:12,letterSpacing:".06em",textTransform:"uppercase"}}>Margen de ganancia</div>
        <div style={{display:"grid",gridTemplateColumns:"1fr 2fr",gap:12,alignItems:"center"}}>
          <InputNum label="Multiplicador" val={multiplicador} onChange={v=>setMultiplicador(Number(v))} placeholder="5"/>
          <div style={{padding:"10px 14px",background:"#0d0d0d",borderRadius:8,border:"1px solid #1e1e1e",fontSize:11,color:"#444",lineHeight:1.8}}>
            <div>× 4 → Precio minorista</div>
            <div>× 3 → Precio mayorista</div>
            <div>× 5 → Precio llave en mano</div>
          </div>
        </div>
      </div>

      <button className="btn" onClick={calcular} style={{marginBottom:20}}>Calcular precio</button>

      {/* Resultado */}
      {resultado && (
        <div className="card">
          <div style={{fontSize:12,color:"#aaa",fontWeight:700,marginBottom:16,letterSpacing:".06em",textTransform:"uppercase"}}>Resultado</div>
          {[
            ["Costo material",         fmtARS(resultado.costoMaterial),  false],
            ["Costo luz",              fmtARS(resultado.costoLuz),        false],
            ["Desgaste máquina",       fmtARS(resultado.costoMaquina),    false],
            ["Margen de error material",fmtARS(resultado.margenErrorARS), false],
            ["Insumos adicionales",    fmtARS(resultado.costoInsumos),    false],
          ].map(([label,val,bold])=>(
            <div key={label} style={{display:"flex",justifyContent:"space-between",padding:"8px 0",borderBottom:"1px solid #1a1a1a",fontSize:12}}>
              <span style={{color:"#666"}}>{label}</span>
              <span style={{color:"#aaa",fontWeight:bold?700:500}}>{val}</span>
            </div>
          ))}
          <div style={{display:"flex",justifyContent:"space-between",padding:"10px 0",borderBottom:"1px solid #1a1a1a",fontSize:12}}>
            <span style={{color:"#888",fontWeight:600}}>Subtotal (costo)</span>
            <span style={{color:"#888",fontWeight:700}}>{fmtARS(resultado.subtotal)}</span>
          </div>
          <div style={{display:"flex",justifyContent:"space-between",padding:"12px 0",borderBottom:"1px solid #252525",fontSize:14}}>
            <span style={{color:"#ccc",fontWeight:700}}>Precio de venta (×{multiplicador})</span>
            <span style={{color:"#4b7d0b",fontWeight:800,fontSize:16}}>{fmtARS(resultado.totalVenta)}</span>
          </div>
          <div style={{display:"flex",justifyContent:"space-between",padding:"10px 0",fontSize:12}}>
            <span style={{color:"#555"}}>Precio MercadoLibre (+80%)</span>
            <span style={{color:"#888",fontWeight:600}}>{fmtARS(resultado.totalML)}</span>
          </div>
          {resultado.tiempoH > 0 && (
            <div style={{marginTop:12,padding:"10px 14px",background:"#0d0d0d",borderRadius:8,border:"1px solid #1e1e1e",fontSize:11,color:"#444",display:"flex",gap:20,flexWrap:"wrap"}}>
              <span>Tiempo: <strong style={{color:"#666"}}>{fmtG(resultado.tiempoH)}hs</strong></span>
              <span>Material: <strong style={{color:"#666"}}>{fmtG(resultado.totalGramos)}g</strong></span>
              <span>Costo/hora: <strong style={{color:"#666"}}>{resultado.tiempoH>0?fmtARS(resultado.subtotal/resultado.tiempoH):"-"}</strong></span>
            </div>
          )}
        </div>
      )}
    </div>
  );
}


// ── EDIT MODAL ────────────────────────────────────────────────────────────────
function EditModal({ value, onSave, onClose }) {
  const [val,setVal]=useState(value);
  return (
    <div className="modal-overlay" onClick={onClose}>
      <div className="modal" onClick={e=>e.stopPropagation()}>
        <div style={{fontSize:13,color:"#aaa",marginBottom:16,fontWeight:600}}>Editar valor</div>
        <input className="inp" value={val} onChange={e=>setVal(e.target.value)} onKeyDown={e=>{if(e.key==="Enter")onSave(val);if(e.key==="Escape")onClose();}} autoFocus/>
        <div style={{display:"flex",gap:8,marginTop:14}}>
          <button onClick={()=>onSave(val)} style={{flex:1,background:"#4b7d0b",color:"#fff",border:"none",borderRadius:8,padding:"10px",fontFamily:"'Montserrat',sans-serif",fontSize:12,cursor:"pointer",fontWeight:700}}>Guardar</button>
          <button onClick={onClose} style={{flex:1,background:"none",color:"#666",border:"1px solid #333",borderRadius:8,padding:"10px",fontFamily:"'Montserrat',sans-serif",fontSize:12,cursor:"pointer"}}>Cancelar</button>
        </div>
      </div>
    </div>
  );
}

// ── MAESTROS ──────────────────────────────────────────────────────────────────
function Maestros({ maestros, filamentos, onAdd, onDelete, onRename, onPrecioUpdate }) {
  const [newVals,setNewVals] = useState({materiales:"",tipos:"",marcas:"",colores:"",estantes:"",posiciones:""});
  const [editing,setEditing] = useState(null);
  const [newBobina,setNewBobina] = useState({marca:"",pesoBobina:""});
  const [editingBobina,setEditingBobina] = useState(null);
  const [editingPrecio,setEditingPrecio] = useState(null);
  const [precioEdit,setPrecioEdit] = useState("");

  const add = lista => {
    const val = newVals[lista].trim();
    if(!val) return;
    if(maestros[lista].includes(val)) return alert("Ya existe.");
    onAdd(lista, val);
    setNewVals(v=>({...v,[lista]:""}));
  };
  const saveEdit = nv => {
    const t = nv.trim();
    if(!t) return;
    if(t===editing.value){setEditing(null);return;}
    if(maestros[editing.lista].includes(t)){alert("Ya existe.");return;}
    onRename(editing.lista, editing.value, t);
    setEditing(null);
  };

  const LISTAS = [
    {key:"materiales",label:"Materiales"},
    {key:"tipos",label:"Tipos de filamento"},
    {key:"marcas",label:"Marcas"},
    {key:"colores",label:"Colores"},
    {key:"estantes",label:"Estantes"},
    {key:"posiciones",label:"Posiciones"},
  ];

  return (
    <div>
      {editing && <EditModal value={editing.value} onSave={saveEdit} onClose={()=>setEditing(null)}/>}
      <div className="section-title">Maestros</div>

      {/* Listas */}
      <div className="maest-grid" style={{display:"grid",gridTemplateColumns:"1fr 1fr",gap:14,marginBottom:14}}>
        {LISTAS.map(({key,label})=>(
          <div key={key} className="card">
            <div style={{fontSize:12,color:"#aaa",fontWeight:700,marginBottom:14,letterSpacing:".04em",textTransform:"uppercase"}}>{label}</div>
            <div style={{display:"flex",flexWrap:"wrap",gap:6,marginBottom:14,minHeight:32}}>
              {maestros[key].map(item=>(
                <span key={item} className="tag">
                  {item}
                  <button className="btn-icon" title="Editar" onClick={()=>setEditing({lista:key,value:item})} style={{color:"#4b7d0b"}}>✎</button>
                  <button className="btn-icon" title="Eliminar" onClick={()=>{if(window.confirm(`¿Eliminás "${item}"?`))onDelete(key,item);}} style={{color:"#555"}}>×</button>
                </span>
              ))}
              {maestros[key].length===0&&<span style={{fontSize:11,color:"#333"}}>Sin elementos</span>}
            </div>
            <div style={{display:"flex",gap:8}}>
              <input className="inp" style={{flex:1,padding:"8px 12px",fontSize:12}} placeholder={`Agregar ${label.toLowerCase()}...`} value={newVals[key]} onChange={e=>setNewVals(v=>({...v,[key]:e.target.value}))} onKeyDown={e=>e.key==="Enter"&&add(key)}/>
              <button className="btn-add" onClick={()=>add(key)}>+ Agregar</button>
            </div>
          </div>
        ))}
      </div>

      {/* Precios */}
      <div className="card" style={{marginBottom:14}}>
        <div style={{fontSize:12,color:"#aaa",fontWeight:700,marginBottom:10,letterSpacing:".04em",textTransform:"uppercase"}}>Precios de filamentos</div>
        <div style={{fontSize:11,color:"#555",marginBottom:14}}>Editá el precio de una bobina de 1kg. El cambio se aplica a todos los filamentos de esa combinación.</div>
        <table style={{width:"100%",borderCollapse:"collapse",fontSize:12}}>
          <thead>
            <tr style={{borderBottom:"1px solid #252525"}}>
              {["Marca","Material","Tipo","Precio / kg","Rollos",""].map((h,i)=>(
                <th key={i} style={{textAlign:"left",padding:"6px 8px",fontSize:10,color:"#444",letterSpacing:".08em",textTransform:"uppercase",fontWeight:600}}>{h}</th>
              ))}
            </tr>
          </thead>
          <tbody>
            {Object.values(
              (filamentos||[]).reduce((acc,f)=>{
                const k=`${f.marca}||${f.material}||${f.tipo}`;
                if(!acc[k]) acc[k]={marca:f.marca,material:f.material,tipo:f.tipo,precio:f.precioUltimo,count:0};
                acc[k].count++;
                return acc;
              },{})
            ).sort((a,b)=>a.marca.localeCompare(b.marca)||a.material.localeCompare(b.material)).map((row,i)=>{
              const isEditing = editingPrecio && editingPrecio.marca===row.marca && editingPrecio.material===row.material && editingPrecio.tipo===row.tipo;
              return (
                <tr key={i} style={{borderBottom:"1px solid #1a1a1a"}}>
                  <td style={{padding:"8px",color:"#ccc",fontWeight:500}}>{row.marca}</td>
                  <td style={{padding:"8px",color:"#888"}}>{row.material}</td>
                  <td style={{padding:"8px",color:"#666"}}>{row.tipo}</td>
                  <td style={{padding:"8px 4px"}}>
                    {isEditing
                      ? <input className="inp" type="number" style={{padding:"5px 10px",fontSize:12,width:120}} value={precioEdit} onChange={e=>setPrecioEdit(e.target.value)} onKeyDown={e=>{if(e.key==="Enter"&&precioEdit){onPrecioUpdate(row.marca,row.material,row.tipo,Number(precioEdit));setEditingPrecio(null);}if(e.key==="Escape")setEditingPrecio(null);}} autoFocus/>
                      : <span style={{color:"#4b7d0b",fontWeight:700}}>{fmtARS(row.precio)}</span>
                    }
                  </td>
                  <td style={{padding:"8px",color:"#444",fontSize:11}}>{row.count} rollo{row.count!==1?"s":""}</td>
                  <td style={{padding:"8px 4px"}}>
                    {isEditing
                      ? <div style={{display:"flex",gap:6}}>
                          <button className="btn-add" onClick={()=>{if(precioEdit){onPrecioUpdate(row.marca,row.material,row.tipo,Number(precioEdit));setEditingPrecio(null);}}} style={{borderColor:"#4b7d0b",color:"#4b7d0b"}}>✓</button>
                          <button className="btn-icon" style={{color:"#555"}} onClick={()=>setEditingPrecio(null)}>✕</button>
                        </div>
                      : <button className="btn-icon" style={{color:"#4b7d0b"}} onClick={()=>{setEditingPrecio({marca:row.marca,material:row.material,tipo:row.tipo});setPrecioEdit(String(row.precio));}}>✎</button>
                    }
                  </td>
                </tr>
              );
            })}
          </tbody>
        </table>
      </div>

      {/* Pesos de bobinas */}
      <div className="card">
        <div style={{fontSize:12,color:"#aaa",fontWeight:700,marginBottom:14,letterSpacing:".04em",textTransform:"uppercase"}}>Pesos de bobinas vacías</div>
        <table style={{width:"100%",borderCollapse:"collapse",fontSize:12}}>
          <thead>
            <tr style={{borderBottom:"1px solid #252525"}}>
              {["Marca bobina","Peso (g)",""].map(h=>(
                <th key={h} style={{textAlign:"left",padding:"6px 8px",fontSize:10,color:"#444",letterSpacing:".08em",textTransform:"uppercase",fontWeight:600}}>{h}</th>
              ))}
            </tr>
          </thead>
          <tbody>
            {(maestros.bobinas||[]).map((b,i)=>(
              <tr key={i} style={{borderBottom:"1px solid #1a1a1a"}}>
                {editingBobina===i ? (
                  <>
                    <td style={{padding:"6px 4px"}}><input className="inp" style={{padding:"6px 10px",fontSize:12}} value={b.marca} onChange={e=>{const nb=[...maestros.bobinas];nb[i]={...nb[i],marca:e.target.value};onAdd("bobinas_update",nb);}}/></td>
                    <td style={{padding:"6px 4px"}}><input className="inp" style={{padding:"6px 10px",fontSize:12,width:100}} type="number" value={b.pesoBobina} onChange={e=>{const nb=[...maestros.bobinas];nb[i]={...nb[i],pesoBobina:Number(e.target.value)};onAdd("bobinas_update",nb);}}/></td>
                    <td style={{padding:"6px 4px"}}><button className="btn-add" onClick={()=>setEditingBobina(null)}>✓ Listo</button></td>
                  </>
                ) : (
                  <>
                    <td style={{padding:"8px",color:"#ccc",fontWeight:500}}>{b.marca}</td>
                    <td style={{padding:"8px",color:"#4b7d0b",fontWeight:700}}>{fmtG(b.pesoBobina)}g</td>
                    <td style={{padding:"8px"}}>
                      <div style={{display:"flex",gap:6}}>
                        <button className="btn-icon" style={{color:"#4b7d0b"}} onClick={()=>setEditingBobina(i)}>✎</button>
                        <button className="btn-icon" style={{color:"#555"}} onClick={()=>{if(window.confirm(`¿Eliminás "${b.marca}"?`)){const nb=maestros.bobinas.filter((_,j)=>j!==i);onAdd("bobinas_update",nb);}}}>×</button>
                      </div>
                    </td>
                  </>
                )}
              </tr>
            ))}
          </tbody>
        </table>
        <div style={{display:"flex",gap:8,marginTop:14}}>
          <input className="inp" style={{flex:2,padding:"8px 12px",fontSize:12}} placeholder="Marca de bobina..." value={newBobina.marca} onChange={e=>setNewBobina(v=>({...v,marca:e.target.value}))}/>
          <input className="inp" style={{width:110,padding:"8px 12px",fontSize:12}} type="number" placeholder="Peso (g)" value={newBobina.pesoBobina} onChange={e=>setNewBobina(v=>({...v,pesoBobina:e.target.value}))}/>
          <button className="btn-add" onClick={()=>{
            if(!newBobina.marca||!newBobina.pesoBobina) return;
            onAdd("bobinas_update",[...(maestros.bobinas||[]),{marca:newBobina.marca,pesoBobina:Number(newBobina.pesoBobina)}]);
            setNewBobina({marca:"",pesoBobina:""});
          }}>+ Agregar</button>
        </div>
      </div>
    </div>
  );
}

// ── RECETAS ───────────────────────────────────────────────────────────────────
function Recetas({ recetas, onSave, toast }) {
  const [modal, setModal] = useState(null); // null | 'new' | receta
  const [ver, setVer]     = useState(null); // receta para ver detalle
  const [cantidades, setCantidades] = useState({}); // {id: cantidad}

  const setCant = (id, v) => setCantidades(c=>({...c,[id]:v}));

  return (
    <div>
      <div style={{display:"flex",justifyContent:"space-between",alignItems:"center",marginBottom:24}}>
        <div className="section-title" style={{marginBottom:0}}>Recetas de productos</div>
        <button className="btn" onClick={()=>setModal({})}>+ Nueva receta</button>
      </div>

      {recetas.length===0
        ? <div className="card" style={{textAlign:"center",padding:40,color:"#333"}}>No hay recetas todavía. Creá la primera.</div>
        : <div className="grid-3" style={{display:"grid",gridTemplateColumns:"repeat(3,1fr)",gap:16}}>
            {recetas.map(r=>{
              const mult = Number(cantidades[r.id])||1;
              return (
                <div key={r.id} className="card" style={{display:"flex",flexDirection:"column",gap:12}}>
                  {r.foto
                    ? <img src={r.foto} alt={r.nombre} style={{width:"100%",height:160,objectFit:"cover",borderRadius:8,border:"1px solid #252525"}}/>
                    : <div style={{width:"100%",height:120,background:"#1a1a1a",borderRadius:8,display:"flex",alignItems:"center",justifyContent:"center",color:"#333",fontSize:12}}>Sin foto</div>
                  }
                  <div>
                    <div style={{fontSize:15,fontWeight:700,color:"#e0e0e0"}}>{r.nombre}</div>
                    {r.categoria && <div style={{fontSize:11,color:"#555",marginTop:2}}>{r.categoria}</div>}
                  </div>
                  {r.precioSugerido && <div style={{fontSize:14,color:"#4b7d0b",fontWeight:700}}>{fmtARS(r.precioSugerido)}</div>}

                  {/* Cantidad multiplier */}
                  <div style={{display:"flex",alignItems:"center",gap:8}}>
                    <div className="lbl" style={{marginBottom:0}}>Cantidad:</div>
                    <input className="inp" type="number" min={1} value={cantidades[r.id]||1} onChange={e=>setCant(r.id,e.target.value)} style={{width:70,padding:"5px 10px",fontSize:13}}/>
                    <div style={{fontSize:10,color:"#555"}}>unidades</div>
                  </div>

                  {/* Filamentos */}
                  {r.filamentos?.length>0 && (
                    <div>
                      <div style={{fontSize:10,color:"#555",letterSpacing:".08em",textTransform:"uppercase",marginBottom:6,fontWeight:600}}>Filamento</div>
                      {r.filamentos.map((f,i)=>(
                        <div key={i} style={{display:"flex",justifyContent:"space-between",fontSize:12,padding:"3px 0"}}>
                          <span style={{color:"#aaa"}}>{f.color} {f.material}</span>
                          <span style={{color:"#4b7d0b",fontWeight:600}}>{fmtG(Number(f.gramos)*mult)}g</span>
                        </div>
                      ))}
                    </div>
                  )}

                  {/* Insumos */}
                  {r.insumos?.length>0 && (
                    <div>
                      <div style={{fontSize:10,color:"#555",letterSpacing:".08em",textTransform:"uppercase",marginBottom:6,fontWeight:600}}>Insumos extra</div>
                      {r.insumos.map((ins,i)=>(
                        <div key={i} style={{display:"flex",justifyContent:"space-between",fontSize:12,padding:"3px 0"}}>
                          <span style={{color:"#aaa"}}>{ins.nombre}</span>
                          <span style={{color:"#888"}}>{fmtG(Number(ins.cantidad)*mult)} {ins.unidad}</span>
                        </div>
                      ))}
                    </div>
                  )}

                  {/* Embalaje */}
                  {r.embalaje?.length>0 && (
                    <div>
                      <div style={{fontSize:10,color:"#555",letterSpacing:".08em",textTransform:"uppercase",marginBottom:6,fontWeight:600}}>Embalaje</div>
                      {r.embalaje.map((e,i)=>(
                        <div key={i} style={{display:"flex",justifyContent:"space-between",fontSize:12,padding:"3px 0"}}>
                          <span style={{color:"#aaa"}}>{e.nombre}</span>
                          <span style={{color:"#888"}}>{fmtG(Number(e.cantidad)*mult)} {e.unidad}</span>
                        </div>
                      ))}
                    </div>
                  )}

                  {/* Tiempo */}
                  {r.tiempo && <div style={{fontSize:11,color:"#555"}}>⏱ {r.tiempo} min{mult>1?` × ${mult} = ${Number(r.tiempo)*mult} min`:""}</div>}

                  {/* Notas */}
                  {r.notas && <div style={{fontSize:11,color:"#444",fontStyle:"italic",borderTop:"1px solid #1a1a1a",paddingTop:8}}>{r.notas}</div>}

                  <div style={{display:"flex",gap:8,marginTop:4}}>
                    <button className="btn-ghost" style={{flex:1}} onClick={()=>setModal(r)}>✎ Editar</button>
                    <button className="btn-danger" onClick={()=>{if(window.confirm(`¿Eliminás "${r.nombre}"?`))onSave(recetas.filter(x=>x.id!==r.id));}}>×</button>
                  </div>
                </div>
              );
            })}
          </div>
      }

      {modal!==null && (
        <RecetaModal
          receta={modal}
          onSave={r=>{
            if(r.id) onSave(recetas.map(x=>x.id===r.id?r:x));
            else onSave([...recetas,{...r,id:uid()}]);
            setModal(null); toast("✓ Receta guardada");
          }}
          onClose={()=>setModal(null)}
        />
      )}
    </div>
  );
}

function RecetaModal({ receta, onSave, onClose }) {
  const [form, setForm] = useState({
    nombre:"", categoria:"", precioSugerido:"", tiempo:"", notas:"", foto:"",
    filamentos:[{color:"",material:"PLA",gramos:""}],
    insumos:[],
    embalaje:[],
    ...receta
  });
  const set = (k,v) => setForm(f=>({...f,[k]:v}));

  const setFil   = (i,k,v) => setForm(f=>({...f,filamentos:f.filamentos.map((x,idx)=>idx===i?{...x,[k]:v}:x)}));
  const addFil   = () => setForm(f=>({...f,filamentos:[...f.filamentos,{color:"",material:"PLA",gramos:""}]}));
  const remFil   = i => setForm(f=>({...f,filamentos:f.filamentos.filter((_,idx)=>idx!==i)}));

  const setIns   = (arr,k) => (i,fk,v) => setForm(f=>({...f,[k]:f[k].map((x,idx)=>idx===i?{...x,[fk]:v}:x)}));
  const addIns   = k => setForm(f=>({...f,[k]:[...f[k],{nombre:"",cantidad:"1",unidad:"u"}]}));
  const remIns   = (k,i) => setForm(f=>({...f,[k]:f[k].filter((_,idx)=>idx!==i)}));

  const handleFoto = e => {
    const file = e.target.files[0];
    if (!file) return;
    const reader = new FileReader();
    reader.onload = ev => set("foto", ev.target.result);
    reader.readAsDataURL(file);
  };

  const submit = () => {
    if (!form.nombre.trim()) return alert("El nombre es obligatorio.");
    onSave(form);
  };

  return (
    <div className="modal-bg" onClick={onClose}>
      <div className="modal" onClick={e=>e.stopPropagation()}>
        <div style={{fontSize:15,fontWeight:700,color:"#fff",marginBottom:20}}>{form.id?"Editar receta":"Nueva receta"}</div>

        <div className="grid-2" style={{display:"grid",gridTemplateColumns:"1fr 1fr",gap:12,marginBottom:12}}>
          <div style={{gridColumn:"1/-1"}}><div className="lbl">Nombre *</div><input className="inp" value={form.nombre} onChange={e=>set("nombre",e.target.value)}/></div>
          <div><div className="lbl">Categoría</div><input className="inp" placeholder="Ej: Veladores" value={form.categoria} onChange={e=>set("categoria",e.target.value)}/></div>
          <div><div className="lbl">Precio sugerido (ARS)</div><input className="inp" type="number" value={form.precioSugerido} onChange={e=>set("precioSugerido",e.target.value)}/></div>
          <div><div className="lbl">Tiempo de impresión (min)</div><input className="inp" type="number" value={form.tiempo} onChange={e=>set("tiempo",e.target.value)}/></div>
          <div>
            <div className="lbl">Foto del producto</div>
            <input type="file" accept="image/*" onChange={handleFoto} style={{fontSize:11,color:"#666"}}/>
            {form.foto && <img src={form.foto} alt="" style={{width:"100%",height:80,objectFit:"cover",borderRadius:6,marginTop:6}}/>}
          </div>
        </div>

        {/* Filamentos */}
        <div style={{marginBottom:14}}>
          <div style={{display:"flex",justifyContent:"space-between",alignItems:"center",marginBottom:8}}>
            <div style={{fontSize:11,color:"#aaa",fontWeight:700,textTransform:"uppercase",letterSpacing:".06em"}}>Filamentos</div>
            <button className="btn-ghost" onClick={addFil}>+ Agregar</button>
          </div>
          {form.filamentos.map((f,i)=>(
            <div key={i} style={{display:"grid",gridTemplateColumns:"1fr 1fr 80px 28px",gap:8,marginBottom:8,alignItems:"flex-end"}}>
              <div><div className="lbl">Color</div><input className="inp" style={{padding:"8px 10px",fontSize:12}} placeholder="Ej: Negro" value={f.color} onChange={e=>setFil(i,"color",e.target.value)}/></div>
              <div><div className="lbl">Material</div><input className="inp" style={{padding:"8px 10px",fontSize:12}} placeholder="PLA" value={f.material} onChange={e=>setFil(i,"material",e.target.value)}/></div>
              <div><div className="lbl">Gramos</div><input className="inp" type="number" style={{padding:"8px 10px",fontSize:12}} value={f.gramos} onChange={e=>setFil(i,"gramos",e.target.value)}/></div>
              {form.filamentos.length>1 && <button className="btn-icon" onClick={()=>remFil(i)} style={{marginBottom:2}}>×</button>}
            </div>
          ))}
        </div>

        {/* Insumos */}
        {[["insumos","Insumos extra"],["embalaje","Embalaje"]].map(([k,label])=>(
          <div key={k} style={{marginBottom:14}}>
            <div style={{display:"flex",justifyContent:"space-between",alignItems:"center",marginBottom:8}}>
              <div style={{fontSize:11,color:"#aaa",fontWeight:700,textTransform:"uppercase",letterSpacing:".06em"}}>{label}</div>
              <button className="btn-ghost" onClick={()=>addIns(k)}>+ Agregar</button>
            </div>
            {(form[k]||[]).map((ins,i)=>(
              <div key={i} style={{display:"grid",gridTemplateColumns:"1fr 80px 70px 28px",gap:8,marginBottom:8,alignItems:"flex-end"}}>
                <div><div className="lbl">Nombre</div><input className="inp" style={{padding:"8px 10px",fontSize:12}} placeholder="Ej: Spray" value={ins.nombre} onChange={e=>setIns(form[k],k)(i,"nombre",e.target.value)}/></div>
                <div><div className="lbl">Cantidad</div><input className="inp" type="number" style={{padding:"8px 10px",fontSize:12}} value={ins.cantidad} onChange={e=>setIns(form[k],k)(i,"cantidad",e.target.value)}/></div>
                <div><div className="lbl">Unidad</div><input className="inp" style={{padding:"8px 10px",fontSize:12}} placeholder="u/ml/g" value={ins.unidad} onChange={e=>setIns(form[k],k)(i,"unidad",e.target.value)}/></div>
                <button className="btn-icon" onClick={()=>remIns(k,i)} style={{marginBottom:2}}>×</button>
              </div>
            ))}
          </div>
        ))}

        <div style={{marginBottom:14}}><div className="lbl">Notas de armado</div><textarea className="inp" value={form.notas} onChange={e=>set("notas",e.target.value)} placeholder="Pasos, tips, advertencias..."/></div>

        <div style={{display:"flex",gap:8,marginTop:8}}>
          <button className="btn" style={{flex:1}} onClick={submit}>Guardar</button>
          <button className="btn-ghost" onClick={onClose}>Cancelar</button>
        </div>
      </div>
    </div>
  );
}

// ── INSUMOS ───────────────────────────────────────────────────────────────────
function Insumos({ insumos, onSave, toast }) {
  const [modal, setModal] = useState(null);
  const [movModal, setMovModal] = useState(null);
  const CATEGORIAS = ["Adhesión","Embalaje","Limpieza","Electricidad","Herramientas","Otros"];

  const registrarMov = (id, tipo, cantidad, nota) => {
    const nuevos = insumos.map(ins => {
      if (ins.id !== id) return ins;
      const nuevo = tipo==="entrada"
        ? (Number(ins.stock)||0) + Number(cantidad)
        : Math.max(0,(Number(ins.stock)||0) - Number(cantidad));
      return {...ins, stock:nuevo, movimientos:[...(ins.movimientos||[]),{tipo,cantidad:Number(cantidad),nota,fecha:new Date().toISOString()}]};
    });
    onSave(nuevos);
    toast(`✓ Movimiento registrado`);
    setMovModal(null);
  };

  return (
    <div>
      <div style={{display:"flex",justifyContent:"space-between",alignItems:"center",marginBottom:24}}>
        <div className="section-title" style={{marginBottom:0}}>Control de insumos</div>
        <button className="btn" onClick={()=>setModal({})}>+ Nuevo insumo</button>
      </div>

      {CATEGORIAS.map(cat=>{
        const items = insumos.filter(i=>i.categoria===cat);
        if(items.length===0) return null;
        return (
          <div key={cat} style={{marginBottom:24}}>
            <div style={{fontSize:11,color:"#555",letterSpacing:".1em",textTransform:"uppercase",fontWeight:700,marginBottom:10}}>{cat}</div>
            <div className="card" style={{padding:0}}>
              {items.map((ins,idx)=>{
                const bajo = ins.stockMinimo && (Number(ins.stock)||0) < Number(ins.stockMinimo);
                return (
                  <div key={ins.id} style={{display:"flex",justifyContent:"space-between",alignItems:"center",padding:"14px 20px",borderBottom:idx<items.length-1?"1px solid #1a1a1a":"none"}}>
                    <div>
                      <div style={{fontSize:13,color:"#e0e0e0",fontWeight:600}}>{ins.nombre}</div>
                      {ins.proveedor && <div style={{fontSize:11,color:"#444",marginTop:2}}>{ins.proveedor}</div>}
                    </div>
                    <div style={{display:"flex",alignItems:"center",gap:12}}>
                      <div style={{textAlign:"right"}}>
                        <div style={{fontSize:14,color:bajo?"#cc4444":"#4b7d0b",fontWeight:700}}>{fmtG(Number(ins.stock)||0)} {ins.unidad}</div>
                        {bajo && <div style={{fontSize:9,color:"#cc4444",fontWeight:700}}>⚠ STOCK BAJO</div>}
                        {ins.precioUnitario && <div style={{fontSize:10,color:"#444",marginTop:1}}>{fmtARS(ins.precioUnitario)}/{ins.unidad}</div>}
                      </div>
                      <div style={{display:"flex",gap:4}}>
                        <button className="btn-ghost" style={{fontSize:10,padding:"4px 8px"}} onClick={()=>setMovModal({...ins,movTipo:"entrada"})}>+ Entrada</button>
                        <button className="btn-ghost" style={{fontSize:10,padding:"4px 8px"}} onClick={()=>setMovModal({...ins,movTipo:"salida"})}>- Salida</button>
                        <button className="btn-icon" onClick={()=>setModal(ins)}>✎</button>
                        <button className="btn-icon" onClick={()=>{if(window.confirm(`¿Eliminás "${ins.nombre}"?`))onSave(insumos.filter(x=>x.id!==ins.id));}}>×</button>
                      </div>
                    </div>
                  </div>
                );
              })}
            </div>
          </div>
        );
      })}

      {insumos.filter(i=>!i.categoria||!CATEGORIAS.includes(i.categoria)).length>0 && (
        <div style={{marginBottom:24}}>
          <div style={{fontSize:11,color:"#555",letterSpacing:".1em",textTransform:"uppercase",fontWeight:700,marginBottom:10}}>Sin categoría</div>
          <div className="card">
            {insumos.filter(i=>!i.categoria||!CATEGORIAS.includes(i.categoria)).map(ins=>(
              <div key={ins.id} className="row-item">
                <span style={{fontSize:13,color:"#ccc"}}>{ins.nombre}</span>
                <div style={{display:"flex",gap:8,alignItems:"center"}}>
                  <span style={{fontSize:13,color:"#4b7d0b",fontWeight:700}}>{fmtG(Number(ins.stock)||0)} {ins.unidad}</span>
                  <button className="btn-icon" onClick={()=>setModal(ins)}>✎</button>
                </div>
              </div>
            ))}
          </div>
        </div>
      )}

      {insumos.length===0 && <div className="card" style={{textAlign:"center",padding:40,color:"#333"}}>No hay insumos cargados.</div>}

      {modal!==null && (
        <InsumoModal
          insumo={modal}
          onSave={ins=>{
            if(ins.id) onSave(insumos.map(x=>x.id===ins.id?ins:x));
            else onSave([...insumos,{...ins,id:uid(),stock:ins.stockInicial||0,movimientos:[]}]);
            setModal(null); toast("✓ Insumo guardado");
          }}
          onClose={()=>setModal(null)}
        />
      )}

      {movModal && (
        <MovModal
          item={movModal}
          onSave={(cant,nota)=>registrarMov(movModal.id,movModal.movTipo,cant,nota)}
          onClose={()=>setMovModal(null)}
        />
      )}
    </div>
  );
}

function InsumoModal({ insumo, onSave, onClose }) {
  const CATS = ["Adhesión","Embalaje","Limpieza","Electricidad","Herramientas","Otros"];
  const [form, setForm] = useState({nombre:"",categoria:"",unidad:"u",stock:0,stockMinimo:"",precioUnitario:"",proveedor:"",...insumo});
  const set = (k,v) => setForm(f=>({...f,[k]:v}));
  return (
    <div className="modal-bg" onClick={onClose}>
      <div className="modal" onClick={e=>e.stopPropagation()}>
        <div style={{fontSize:15,fontWeight:700,color:"#fff",marginBottom:20}}>{form.id?"Editar insumo":"Nuevo insumo"}</div>
        <div className="grid-2" style={{display:"grid",gridTemplateColumns:"1fr 1fr",gap:12}}>
          <div style={{gridColumn:"1/-1"}}><div className="lbl">Nombre *</div><input className="inp" value={form.nombre} onChange={e=>set("nombre",e.target.value)}/></div>
          <div><div className="lbl">Categoría</div><select className="inp" value={form.categoria} onChange={e=>set("categoria",e.target.value)}><option value="">—</option>{CATS.map(c=><option key={c}>{c}</option>)}</select></div>
          <div><div className="lbl">Unidad</div><input className="inp" placeholder="u / ml / g / m" value={form.unidad} onChange={e=>set("unidad",e.target.value)}/></div>
          {!form.id && <div><div className="lbl">Stock inicial</div><input className="inp" type="number" value={form.stockInicial||""} onChange={e=>set("stockInicial",e.target.value)}/></div>}
          <div><div className="lbl">Stock mínimo (alerta)</div><input className="inp" type="number" value={form.stockMinimo} onChange={e=>set("stockMinimo",e.target.value)}/></div>
          <div><div className="lbl">Precio unitario (ARS)</div><input className="inp" type="number" value={form.precioUnitario} onChange={e=>set("precioUnitario",e.target.value)}/></div>
          <div style={{gridColumn:"1/-1"}}><div className="lbl">Proveedor</div><input className="inp" value={form.proveedor} onChange={e=>set("proveedor",e.target.value)}/></div>
        </div>
        <div style={{display:"flex",gap:8,marginTop:20}}>
          <button className="btn" style={{flex:1}} onClick={()=>{if(!form.nombre.trim())return alert("Nombre requerido.");onSave(form);}}>Guardar</button>
          <button className="btn-ghost" onClick={onClose}>Cancelar</button>
        </div>
      </div>
    </div>
  );
}

function MovModal({ item, onSave, onClose }) {
  const [cant, setCant] = useState("");
  const [nota, setNota] = useState("");
  return (
    <div className="modal-bg" onClick={onClose}>
      <div className="modal" style={{maxWidth:360}} onClick={e=>e.stopPropagation()}>
        <div style={{fontSize:14,fontWeight:700,color:"#fff",marginBottom:4}}>{item.movTipo==="entrada"?"+ Entrada":"- Salida"}: {item.nombre}</div>
        <div style={{fontSize:12,color:"#555",marginBottom:20}}>Stock actual: <span style={{color:"#4b7d0b",fontWeight:700}}>{fmtG(Number(item.stock)||0)} {item.unidad}</span></div>
        <div style={{marginBottom:12}}><div className="lbl">Cantidad ({item.unidad})</div><input className="inp" type="number" min={0} autoFocus value={cant} onChange={e=>setCant(e.target.value)}/></div>
        <div style={{marginBottom:16}}><div className="lbl">Nota (opcional)</div><input className="inp" value={nota} onChange={e=>setNota(e.target.value)} placeholder="Ej: Compra en ferretería"/></div>
        <div style={{display:"flex",gap:8}}>
          <button className="btn" style={{flex:1}} onClick={()=>{if(!cant)return;onSave(cant,nota);}}>Confirmar</button>
          <button className="btn-ghost" onClick={onClose}>Cancelar</button>
        </div>
      </div>
    </div>
  );
}

// ── PRODUCTOS TERMINADOS ──────────────────────────────────────────────────────
function Productos({ productos, recetas, onSave, toast }) {
  const [modal, setModal] = useState(null);

  return (
    <div>
      <div style={{display:"flex",justifyContent:"space-between",alignItems:"center",marginBottom:24}}>
        <div className="section-title" style={{marginBottom:0}}>Stock de productos terminados</div>
        <button className="btn" onClick={()=>setModal({})}>+ Nuevo producto</button>
      </div>

      {productos.length===0
        ? <div className="card" style={{textAlign:"center",padding:40,color:"#333"}}>No hay productos cargados.</div>
        : <div className="grid-4" style={{display:"grid",gridTemplateColumns:"repeat(4,1fr)",gap:12}}>
            {productos.map(p=>{
              const bajo = p.stockMinimo && (Number(p.stock)||0) < Number(p.stockMinimo);
              const receta = recetas.find(r=>r.id===p.recetaId);
              return (
                <div key={p.id} className="card">
                  {p.foto
                    ? <img src={p.foto} alt={p.nombre} style={{width:"100%",height:120,objectFit:"cover",borderRadius:8,marginBottom:10,border:"1px solid #252525"}}/>
                    : <div style={{width:"100%",height:80,background:"#1a1a1a",borderRadius:8,marginBottom:10,display:"flex",alignItems:"center",justifyContent:"center",color:"#333",fontSize:11}}>Sin foto</div>
                  }
                  <div style={{fontSize:14,color:"#e0e0e0",fontWeight:700,marginBottom:4}}>{p.nombre}</div>
                  {p.variante && <div className="tag-chip" style={{marginBottom:8,display:"inline-block"}}>{p.variante}</div>}
                  {receta && <div style={{fontSize:10,color:"#555",marginBottom:8}}>Receta: {receta.nombre}</div>}
                  <div style={{fontSize:20,color:bajo?"#cc4444":"#4b7d0b",fontWeight:800,marginBottom:4}}>{Number(p.stock)||0} <span style={{fontSize:11,fontWeight:400}}>u</span></div>
                  {bajo && <div style={{fontSize:9,color:"#cc4444",fontWeight:700,marginBottom:4}}>⚠ STOCK BAJO</div>}
                  {p.precioVenta && <div style={{fontSize:12,color:"#888",marginBottom:8}}>{fmtARS(p.precioVenta)}</div>}
                  <div style={{display:"flex",gap:6,marginTop:8}}>
                    <button className="btn-ghost" style={{flex:1,fontSize:10,padding:"5px 8px"}} onClick={()=>{const n=prompt("Nuevo stock:");if(n!==null)onSave(productos.map(x=>x.id===p.id?{...x,stock:Number(n)}:x));}}>Ajustar stock</button>
                    <button className="btn-icon" onClick={()=>setModal(p)}>✎</button>
                    <button className="btn-icon" onClick={()=>{if(window.confirm(`¿Eliminás "${p.nombre}"?`))onSave(productos.filter(x=>x.id!==p.id));}}>×</button>
                  </div>
                </div>
              );
            })}
          </div>
      }

      {modal!==null && (
        <ProductoModal
          producto={modal}
          recetas={recetas}
          onSave={p=>{
            if(p.id) onSave(productos.map(x=>x.id===p.id?p:x));
            else onSave([...productos,{...p,id:uid(),stock:p.stockInicial||0}]);
            setModal(null); toast("✓ Producto guardado");
          }}
          onClose={()=>setModal(null)}
        />
      )}
    </div>
  );
}

function ProductoModal({ producto, recetas, onSave, onClose }) {
  const [form, setForm] = useState({nombre:"",variante:"",recetaId:"",precioVenta:"",stockMinimo:"",foto:"",...producto});
  const set = (k,v) => setForm(f=>({...f,[k]:v}));
  const handleFoto = e => { const file=e.target.files[0]; if(!file)return; const r=new FileReader(); r.onload=ev=>set("foto",ev.target.result); r.readAsDataURL(file); };
  return (
    <div className="modal-bg" onClick={onClose}>
      <div className="modal" onClick={e=>e.stopPropagation()}>
        <div style={{fontSize:15,fontWeight:700,color:"#fff",marginBottom:20}}>{form.id?"Editar producto":"Nuevo producto terminado"}</div>
        <div className="grid-2" style={{display:"grid",gridTemplateColumns:"1fr 1fr",gap:12}}>
          <div style={{gridColumn:"1/-1"}}><div className="lbl">Nombre *</div><input className="inp" value={form.nombre} onChange={e=>set("nombre",e.target.value)}/></div>
          <div><div className="lbl">Variante</div><input className="inp" placeholder="Ej: Negro 20cm" value={form.variante} onChange={e=>set("variante",e.target.value)}/></div>
          <div><div className="lbl">Receta asociada</div><select className="inp" value={form.recetaId} onChange={e=>set("recetaId",e.target.value)}><option value="">— Ninguna —</option>{recetas.map(r=><option key={r.id} value={r.id}>{r.nombre}</option>)}</select></div>
          <div><div className="lbl">Precio de venta (ARS)</div><input className="inp" type="number" value={form.precioVenta} onChange={e=>set("precioVenta",e.target.value)}/></div>
          <div><div className="lbl">Stock mínimo (alerta)</div><input className="inp" type="number" value={form.stockMinimo} onChange={e=>set("stockMinimo",e.target.value)}/></div>
          {!form.id && <div><div className="lbl">Stock inicial</div><input className="inp" type="number" value={form.stockInicial||""} onChange={e=>set("stockInicial",e.target.value)}/></div>}
          <div style={{gridColumn:"1/-1"}}><div className="lbl">Foto</div><input type="file" accept="image/*" onChange={handleFoto} style={{fontSize:11,color:"#666"}}/>{form.foto&&<img src={form.foto} alt="" style={{width:"100%",height:80,objectFit:"cover",borderRadius:6,marginTop:6}}/>}</div>
        </div>
        <div style={{display:"flex",gap:8,marginTop:20}}>
          <button className="btn" style={{flex:1}} onClick={()=>{if(!form.nombre.trim())return alert("Nombre requerido.");onSave(form);}}>Guardar</button>
          <button className="btn-ghost" onClick={onClose}>Cancelar</button>
        </div>
      </div>
    </div>
  );
}

// ── VENTAS ────────────────────────────────────────────────────────────────────
function Ventas({ ventas, productos, onSave, onUpdate, toast }) {
  const [modal, setModal] = useState(false);
  const [filtroEstado, setFiltroEstado] = useState("");
  const [filtroCanal, setFiltroCanal]   = useState("");

  const sorted = [...ventas].sort((a,b)=>new Date(b.fecha)-new Date(a.fecha));
  const filtradas = sorted.filter(v=>
    (!filtroEstado||v.estado===filtroEstado)&&
    (!filtroCanal||v.canal===filtroCanal)
  );

  const totalMes = () => {
    const m = new Date().toISOString().slice(0,7);
    return ventas.filter(v=>v.fecha?.startsWith(m)&&v.estado!=="Cancelado").reduce((a,v)=>a+Number(v.precioTotal||0),0);
  };

  const updateEstado = (id, estado) => {
    onUpdate(ventas.map(v=>v.id===id?{...v,estado}:v));
    toast(`✓ Estado actualizado a ${estado}`);
  };

  return (
    <div>
      <div style={{display:"flex",justifyContent:"space-between",alignItems:"center",marginBottom:20}}>
        <div className="section-title" style={{marginBottom:0}}>Ventas</div>
        <button className="btn" onClick={()=>setModal(true)}>+ Nueva venta</button>
      </div>

      {/* Stats */}
      <div className="grid-4" style={{display:"grid",gridTemplateColumns:"repeat(4,1fr)",gap:10,marginBottom:20}}>
        {[
          {label:"Este mes",val:fmtARS(totalMes()),sub:"en ventas"},
          {label:"Total ventas",val:ventas.filter(v=>v.estado!=="Cancelado").length,sub:"confirmadas"},
          {label:"Pendientes",val:ventas.filter(v=>v.estado==="Pendiente"||v.estado==="En producción").length,sub:"por entregar"},
          {label:"Canceladas",val:ventas.filter(v=>v.estado==="Cancelado").length,sub:"este período"},
        ].map((s,i)=>(
          <div key={i} className="card" style={{padding:16}}>
            <div style={{fontSize:22,fontWeight:800,color:"#4b7d0b",letterSpacing:"-0.02em"}}>{s.val}</div>
            <div style={{fontSize:10,color:"#555",textTransform:"uppercase",letterSpacing:".08em",fontWeight:600,marginTop:6}}>{s.label}</div>
            <div style={{fontSize:10,color:"#333",marginTop:2}}>{s.sub}</div>
          </div>
        ))}
      </div>

      {/* Filters */}
      <div style={{display:"flex",gap:8,marginBottom:16,flexWrap:"wrap"}}>
        <select className="inp" style={{width:"auto",padding:"7px 12px",fontSize:12}} value={filtroEstado} onChange={e=>setFiltroEstado(e.target.value)}>
          <option value="">Todos los estados</option>
          {ESTADOS.map(s=><option key={s}>{s}</option>)}
        </select>
        <select className="inp" style={{width:"auto",padding:"7px 12px",fontSize:12}} value={filtroCanal} onChange={e=>setFiltroCanal(e.target.value)}>
          <option value="">Todos los canales</option>
          {CANALES.map(c=><option key={c}>{c}</option>)}
        </select>
        {(filtroEstado||filtroCanal)&&<button className="btn-ghost" onClick={()=>{setFiltroEstado("");setFiltroCanal("");}}>Limpiar</button>}
      </div>

      {filtradas.length===0
        ? <div className="card" style={{textAlign:"center",padding:40,color:"#333"}}>No hay ventas{filtroEstado||filtroCanal?" con estos filtros":""}.</div>
        : <div className="card" style={{padding:0}}>
            {filtradas.map((v,idx)=>{
              const prod = productos.find(p=>p.id===v.productoId);
              const ec = ESTADO_COLOR[v.estado]||"#555";
              return (
                <div key={v.id} style={{padding:"14px 20px",borderBottom:idx<filtradas.length-1?"1px solid #1a1a1a":"none"}}>
                  <div style={{display:"flex",justifyContent:"space-between",alignItems:"flex-start",flexWrap:"wrap",gap:8}}>
                    <div>
                      <div style={{display:"flex",gap:8,alignItems:"center",flexWrap:"wrap",marginBottom:4}}>
                        <span style={{fontSize:13,color:"#e0e0e0",fontWeight:600}}>{v.clienteNombre||"Cliente sin nombre"}</span>
                        <span className="badge" style={{background:`${ec}20`,color:ec,border:`1px solid ${ec}44`}}>{v.estado}</span>
                        <span className="tag-chip">{v.canal}</span>
                      </div>
                      <div style={{fontSize:12,color:"#888"}}>
                        {prod?.nombre||v.productoNombre||"—"} {v.variante&&`· ${v.variante}`} × {v.cantidad}
                      </div>
                      {v.clienteContacto && <div style={{fontSize:11,color:"#444",marginTop:2}}>{v.clienteContacto}</div>}
                      {v.notas && <div style={{fontSize:11,color:"#444",fontStyle:"italic",marginTop:2}}>{v.notas}</div>}
                    </div>
                    <div style={{textAlign:"right"}}>
                      <div style={{fontSize:16,color:"#4b7d0b",fontWeight:800}}>{fmtARS(v.precioTotal||0)}</div>
                      {v.costoEnvio>0 && <div style={{fontSize:10,color:"#555"}}>Envío: {fmtARS(v.costoEnvio)}</div>}
                      <div style={{fontSize:10,color:"#444",marginTop:2}}>{v.fecha?new Date(v.fecha).toLocaleDateString("es-AR",{day:"2-digit",month:"short",year:"numeric"}):""}</div>
                      <div style={{marginTop:6}}>
                        <select style={{background:"#1a1a1a",border:"1px solid #252525",borderRadius:6,padding:"3px 8px",fontSize:11,color:ec,cursor:"pointer",fontFamily:"Montserrat,sans-serif",fontWeight:600}} value={v.estado} onChange={e=>updateEstado(v.id,e.target.value)}>
                          {ESTADOS.map(s=><option key={s} style={{color:"#e0e0e0"}}>{s}</option>)}
                        </select>
                      </div>
                    </div>
                  </div>
                </div>
              );
            })}
          </div>
      }

      {modal && (
        <VentaModal
          productos={productos}
          onSave={v=>{onSave(v);setModal(false);}}
          onClose={()=>setModal(false)}
        />
      )}
    </div>
  );
}

function VentaModal({ productos, onSave, onClose }) {
  const [form, setForm] = useState({canal:"MercadoLibre",productoId:"",variante:"",cantidad:1,precioUnitario:"",costoEnvio:0,estado:"Pendiente",clienteNombre:"",clienteContacto:"",notas:""});
  const set=(k,v)=>setForm(f=>({...f,[k]:v}));
  const prod = productos.find(p=>p.id===form.productoId);
  const precioTotal = (Number(form.precioUnitario)||0)*Number(form.cantidad) + Number(form.costoEnvio||0);
  return (
    <div className="modal-bg" onClick={onClose}>
      <div className="modal" onClick={e=>e.stopPropagation()}>
        <div style={{fontSize:15,fontWeight:700,color:"#fff",marginBottom:20}}>Nueva venta</div>
        <div className="grid-2" style={{display:"grid",gridTemplateColumns:"1fr 1fr",gap:12}}>
          <div><div className="lbl">Canal</div><select className="inp" value={form.canal} onChange={e=>set("canal",e.target.value)}>{CANALES.map(c=><option key={c}>{c}</option>)}</select></div>
          <div><div className="lbl">Estado</div><select className="inp" value={form.estado} onChange={e=>set("estado",e.target.value)}>{ESTADOS.map(s=><option key={s}>{s}</option>)}</select></div>
          <div style={{gridColumn:"1/-1"}}><div className="lbl">Producto</div><select className="inp" value={form.productoId} onChange={e=>set("productoId",e.target.value)}><option value="">— Seleccioná —</option>{productos.map(p=><option key={p.id} value={p.id}>{p.nombre}{p.variante?` · ${p.variante}`:""}</option>)}</select></div>
          {prod&&<div style={{gridColumn:"1/-1",background:"#0d0d0d",borderRadius:8,padding:"8px 12px",fontSize:11,color:"#555",border:"1px solid #1e1e1e"}}>Stock disponible: <span style={{color:"#4b7d0b",fontWeight:700}}>{prod.stock||0} u</span></div>}
          <div><div className="lbl">Cantidad</div><input className="inp" type="number" min={1} value={form.cantidad} onChange={e=>set("cantidad",e.target.value)}/></div>
          <div><div className="lbl">Precio unitario (ARS)</div><input className="inp" type="number" value={form.precioUnitario} onChange={e=>set("precioUnitario",e.target.value)}/></div>
          <div><div className="lbl">Costo de envío (ARS)</div><input className="inp" type="number" value={form.costoEnvio} onChange={e=>set("costoEnvio",e.target.value)}/></div>
          <div style={{display:"flex",alignItems:"flex-end"}}><div style={{padding:"10px 14px",background:"#0d0d0d",borderRadius:8,border:"1px solid #1e1e1e",fontSize:12,color:"#4b7d0b",fontWeight:700,width:"100%"}}>Total: {fmtARS(precioTotal)}</div></div>
          <div><div className="lbl">Nombre del cliente</div><input className="inp" value={form.clienteNombre} onChange={e=>set("clienteNombre",e.target.value)}/></div>
          <div><div className="lbl">Contacto (tel / IG / ML)</div><input className="inp" value={form.clienteContacto} onChange={e=>set("clienteContacto",e.target.value)}/></div>
          <div style={{gridColumn:"1/-1"}}><div className="lbl">Notas</div><input className="inp" value={form.notas} onChange={e=>set("notas",e.target.value)} placeholder="Personalización, dirección, etc."/></div>
        </div>
        <div style={{display:"flex",gap:8,marginTop:20}}>
          <button className="btn" style={{flex:1}} onClick={()=>{if(!form.productoId&&!form.precioUnitario)return alert("Completá los campos requeridos.");onSave({...form,precioTotal,productoNombre:prod?.nombre||""});}}>Registrar venta</button>
          <button className="btn-ghost" onClick={onClose}>Cancelar</button>
        </div>
      </div>
    </div>
  );
}

// ── PROVEEDORES ───────────────────────────────────────────────────────────────
function Proveedores({ proveedores, insumos, onSave, toast }) {
  const [modal, setModal]     = useState(null);
  const [pedidoModal, setPedidoModal] = useState(null);

  return (
    <div>
      <div style={{display:"flex",justifyContent:"space-between",alignItems:"center",marginBottom:24}}>
        <div className="section-title" style={{marginBottom:0}}>Proveedores</div>
        <button className="btn" onClick={()=>setModal({})}>+ Nuevo proveedor</button>
      </div>

      {proveedores.length===0
        ? <div className="card" style={{textAlign:"center",padding:40,color:"#333"}}>No hay proveedores cargados.</div>
        : <div className="grid-2" style={{display:"grid",gridTemplateColumns:"repeat(2,1fr)",gap:16}}>
            {proveedores.map(p=>(
              <div key={p.id} className="card">
                <div style={{display:"flex",justifyContent:"space-between",alignItems:"flex-start",marginBottom:12}}>
                  <div>
                    <div style={{fontSize:15,fontWeight:700,color:"#e0e0e0"}}>{p.nombre}</div>
                    {p.tipo && <span className="tag-chip" style={{marginTop:4,display:"inline-block"}}>{p.tipo}</span>}
                  </div>
                  <div style={{display:"flex",gap:4}}>
                    <button className="btn-icon" onClick={()=>setModal(p)}>✎</button>
                    <button className="btn-icon" onClick={()=>{if(window.confirm(`¿Eliminás "${p.nombre}"?`))onSave(proveedores.filter(x=>x.id!==p.id));}}>×</button>
                  </div>
                </div>
                {p.contacto && <div style={{fontSize:12,color:"#555",marginBottom:4}}>📞 {p.contacto}</div>}
                {p.web && <div style={{fontSize:12,color:"#4b7d0b",marginBottom:4}}><a href={p.web} target="_blank" rel="noreferrer" style={{color:"#4b7d0b"}}>🌐 {p.web}</a></div>}
                {p.productos && <div style={{fontSize:12,color:"#444",marginBottom:8}}>Productos: {p.productos}</div>}
                {p.notas && <div style={{fontSize:11,color:"#444",fontStyle:"italic",borderTop:"1px solid #1a1a1a",paddingTop:8,marginTop:4}}>{p.notas}</div>}

                {/* Pedidos pendientes */}
                {(p.pedidos||[]).filter(pd=>pd.estado!=="Recibido").length>0 && (
                  <div style={{marginTop:10,borderTop:"1px solid #1a1a1a",paddingTop:10}}>
                    <div style={{fontSize:10,color:"#555",letterSpacing:".08em",textTransform:"uppercase",fontWeight:600,marginBottom:6}}>Pedidos pendientes</div>
                    {p.pedidos.filter(pd=>pd.estado!=="Recibido").map((pd,i)=>(
                      <div key={i} style={{display:"flex",justifyContent:"space-between",fontSize:11,padding:"4px 0",borderBottom:"1px solid #1a1a1a"}}>
                        <span style={{color:"#aaa"}}>{pd.descripcion}</span>
                        <div style={{display:"flex",gap:8,alignItems:"center"}}>
                          <span className="badge" style={{background:"#a0700020",color:"#a07000",border:"1px solid #a0700040"}}>{pd.estado}</span>
                          <button style={{background:"none",border:"none",cursor:"pointer",color:"#4b7d0b",fontSize:10,fontFamily:"Montserrat,sans-serif",fontWeight:600}} onClick={()=>onSave(proveedores.map(pr=>pr.id===p.id?{...pr,pedidos:pr.pedidos.map((x,j)=>j===i?{...x,estado:"Recibido"}:x)}:pr))}>✓ Recibido</button>
                        </div>
                      </div>
                    ))}
                  </div>
                )}

                <button className="btn-ghost" style={{marginTop:10,width:"100%",fontSize:11}} onClick={()=>setPedidoModal(p)}>+ Nuevo pedido</button>
              </div>
            ))}
          </div>
      }

      {modal!==null && (
        <ProveedorModal
          proveedor={modal}
          onSave={pr=>{
            if(pr.id) onSave(proveedores.map(x=>x.id===pr.id?pr:x));
            else onSave([...proveedores,{...pr,id:uid(),pedidos:[]}]);
            setModal(null); toast("✓ Proveedor guardado");
          }}
          onClose={()=>setModal(null)}
        />
      )}

      {pedidoModal && (
        <PedidoModal
          proveedor={pedidoModal}
          onSave={(desc,monto)=>{
            onSave(proveedores.map(p=>p.id===pedidoModal.id?{...p,pedidos:[...(p.pedidos||[]),{descripcion:desc,monto,estado:"Pendiente",fecha:new Date().toISOString()}]}:p));
            setPedidoModal(null); toast("✓ Pedido registrado");
          }}
          onClose={()=>setPedidoModal(null)}
        />
      )}
    </div>
  );
}

function ProveedorModal({ proveedor, onSave, onClose }) {
  const TIPOS = ["Filamento","Embalaje","Electricidad","Herramientas","General"];
  const [form, setForm] = useState({nombre:"",tipo:"",contacto:"",web:"",productos:"",notas:"",...proveedor});
  const set=(k,v)=>setForm(f=>({...f,[k]:v}));
  return (
    <div className="modal-bg" onClick={onClose}>
      <div className="modal" onClick={e=>e.stopPropagation()}>
        <div style={{fontSize:15,fontWeight:700,color:"#fff",marginBottom:20}}>{form.id?"Editar proveedor":"Nuevo proveedor"}</div>
        <div className="grid-2" style={{display:"grid",gridTemplateColumns:"1fr 1fr",gap:12}}>
          <div style={{gridColumn:"1/-1"}}><div className="lbl">Nombre *</div><input className="inp" value={form.nombre} onChange={e=>set("nombre",e.target.value)}/></div>
          <div><div className="lbl">Tipo</div><select className="inp" value={form.tipo} onChange={e=>set("tipo",e.target.value)}><option value="">—</option>{TIPOS.map(t=><option key={t}>{t}</option>)}</select></div>
          <div><div className="lbl">Contacto</div><input className="inp" placeholder="Tel / email / IG" value={form.contacto} onChange={e=>set("contacto",e.target.value)}/></div>
          <div style={{gridColumn:"1/-1"}}><div className="lbl">Sitio web / tienda</div><input className="inp" value={form.web} onChange={e=>set("web",e.target.value)}/></div>
          <div style={{gridColumn:"1/-1"}}><div className="lbl">Productos que vende</div><input className="inp" placeholder="Ej: PLA, PETG, filamentos especiales" value={form.productos} onChange={e=>set("productos",e.target.value)}/></div>
          <div style={{gridColumn:"1/-1"}}><div className="lbl">Notas</div><textarea className="inp" value={form.notas} onChange={e=>set("notas",e.target.value)} placeholder="Condiciones, descuentos, plazos..."/></div>
        </div>
        <div style={{display:"flex",gap:8,marginTop:20}}>
          <button className="btn" style={{flex:1}} onClick={()=>{if(!form.nombre.trim())return alert("Nombre requerido.");onSave(form);}}>Guardar</button>
          <button className="btn-ghost" onClick={onClose}>Cancelar</button>
        </div>
      </div>
    </div>
  );
}

function PedidoModal({ proveedor, onSave, onClose }) {
  const [desc, setDesc] = useState("");
  const [monto, setMonto] = useState("");
  return (
    <div className="modal-bg" onClick={onClose}>
      <div className="modal" style={{maxWidth:380}} onClick={e=>e.stopPropagation()}>
        <div style={{fontSize:14,fontWeight:700,color:"#fff",marginBottom:4}}>Nuevo pedido a {proveedor.nombre}</div>
        <div style={{fontSize:12,color:"#555",marginBottom:20}}>Se registra como pendiente hasta que lo marcás como recibido.</div>
        <div style={{marginBottom:12}}><div className="lbl">Descripción del pedido</div><input className="inp" autoFocus value={desc} onChange={e=>setDesc(e.target.value)} placeholder="Ej: 3 rollos PLA negro 1kg"/></div>
        <div style={{marginBottom:16}}><div className="lbl">Monto estimado (ARS)</div><input className="inp" type="number" value={monto} onChange={e=>setMonto(e.target.value)}/></div>
        <div style={{display:"flex",gap:8}}>
          <button className="btn" style={{flex:1}} onClick={()=>{if(!desc.trim())return;onSave(desc,monto);}}>Registrar pedido</button>
          <button className="btn-ghost" onClick={onClose}>Cancelar</button>
        </div>
      </div>
    </div>
  );
}

// ── FINANZAS ──────────────────────────────────────────────────────────────────
function Finanzas({ ventas, productos, insumos }) {
  const [periodo, setPeriodo] = useState("mes");

  const filtrar = vs => {
    const now = new Date();
    return vs.filter(v => {
      if(!v.fecha||v.estado==="Cancelado") return false;
      const d = new Date(v.fecha);
      if(periodo==="mes") return d.getMonth()===now.getMonth()&&d.getFullYear()===now.getFullYear();
      if(periodo==="3m") return (now-d)<90*24*60*60*1000;
      if(periodo==="año") return d.getFullYear()===now.getFullYear();
      return true;
    });
  };

  const ventasFiltradas = filtrar(ventas);
  const ingresoTotal    = ventasFiltradas.reduce((a,v)=>a+Number(v.precioTotal||0),0);
  const cantidadVentas  = ventasFiltradas.length;
  const ticketPromedio  = cantidadVentas>0?ingresoTotal/cantidadVentas:0;

  // Ventas por canal
  const porCanal = CANALES.map(c=>({
    canal:c,
    total:ventasFiltradas.filter(v=>v.canal===c).reduce((a,v)=>a+Number(v.precioTotal||0),0),
    count:ventasFiltradas.filter(v=>v.canal===c).length,
  })).filter(c=>c.count>0).sort((a,b)=>b.total-a.total);

  // Ventas por mes (últimos 6)
  const meses = Array.from({length:6},(_,i)=>{
    const d=new Date(); d.setMonth(d.getMonth()-5+i);
    const key=`${d.getFullYear()}-${String(d.getMonth()+1).padStart(2,"0")}`;
    const label=d.toLocaleString("es-AR",{month:"short"}).toUpperCase();
    const total=ventas.filter(v=>v.fecha?.startsWith(key)&&v.estado!=="Cancelado").reduce((a,v)=>a+Number(v.precioTotal||0),0);
    return {label,total};
  });
  const maxTotal = Math.max(...meses.map(m=>m.total),1);

  // Valor inventario
  const valorInventario = productos.reduce((a,p)=>a+(Number(p.stock)||0)*(Number(p.precioVenta)||0),0);
  const valorInsumos    = insumos.reduce((a,ins)=>a+(Number(ins.stock)||0)*(Number(ins.precioUnitario)||0),0);

  // Pedidos pendientes a proveedores
  const pedidosPendientes = [];

  return (
    <div>
      <div style={{display:"flex",justifyContent:"space-between",alignItems:"center",marginBottom:24}}>
        <div className="section-title" style={{marginBottom:0}}>Resumen financiero</div>
        <div style={{display:"flex",gap:6}}>
          {[["mes","Este mes"],["3m","3 meses"],["año","Este año"],["todo","Todo"]].map(([v,l])=>(
            <button key={v} className={periodo===v?"btn":"btn-ghost"} style={{padding:"6px 12px",fontSize:11}} onClick={()=>setPeriodo(v)}>{l}</button>
          ))}
        </div>
      </div>

      {/* KPIs */}
      <div className="grid-4" style={{display:"grid",gridTemplateColumns:"repeat(4,1fr)",gap:10,marginBottom:20}}>
        {[
          {label:"Ingresos",val:fmtARS(ingresoTotal),sub:`${cantidadVentas} ventas`},
          {label:"Ticket promedio",val:fmtARS(ticketPromedio),sub:"por venta"},
          {label:"Inventario terminados",val:fmtARS(valorInventario),sub:"valor en stock"},
          {label:"Inventario insumos",val:fmtARS(valorInsumos),sub:"valor estimado"},
        ].map((s,i)=>(
          <div key={i} className="card" style={{padding:16}}>
            <div style={{fontSize:20,fontWeight:800,color:"#4b7d0b",letterSpacing:"-0.02em"}}>{s.val}</div>
            <div style={{fontSize:10,color:"#555",textTransform:"uppercase",letterSpacing:".08em",fontWeight:600,marginTop:6}}>{s.label}</div>
            <div style={{fontSize:10,color:"#333",marginTop:2}}>{s.sub}</div>
          </div>
        ))}
      </div>

      <div className="grid-2" style={{display:"grid",gridTemplateColumns:"1fr 1fr",gap:16,marginBottom:16}}>
        {/* Gráfico mensual */}
        <div className="card">
          <div style={{fontSize:10,color:"#444",letterSpacing:".1em",textTransform:"uppercase",fontWeight:600,marginBottom:18}}>Ingresos mensuales</div>
          <div style={{display:"flex",gap:6,alignItems:"flex-end",height:80}}>
            {meses.map((m,i)=>(
              <div key={i} style={{flex:1,display:"flex",flexDirection:"column",alignItems:"center",gap:5}}>
                {m.total>0&&<div style={{fontSize:9,color:"#666",fontWeight:600}}>{fmtARS(m.total).replace("$","")}</div>}
                <div style={{width:"100%",borderRadius:3,background:m.total>0?"#4b7d0b":"#1a1a1a",height:`${Math.max(m.total>0?8:3,(m.total/maxTotal)*60)}px`,transition:"height .6s"}}/>
                <div style={{fontSize:9,color:"#444",fontWeight:600}}>{m.label}</div>
              </div>
            ))}
          </div>
        </div>

        {/* Por canal */}
        <div className="card">
          <div style={{fontSize:10,color:"#444",letterSpacing:".1em",textTransform:"uppercase",fontWeight:600,marginBottom:16}}>Ventas por canal</div>
          {porCanal.length===0
            ? <div style={{color:"#333",fontSize:12}}>Sin ventas en este período.</div>
            : porCanal.map(c=>(
              <div key={c.canal} style={{marginBottom:12}}>
                <div style={{display:"flex",justifyContent:"space-between",fontSize:12,marginBottom:4}}>
                  <span style={{color:"#aaa",fontWeight:500}}>{c.canal}</span>
                  <span style={{color:"#4b7d0b",fontWeight:600}}>{fmtARS(c.total)} <span style={{color:"#444",fontWeight:400}}>({c.count})</span></span>
                </div>
                <div style={{height:3,background:"#1a1a1a",borderRadius:2,overflow:"hidden"}}>
                  <div style={{height:"100%",background:"#4b7d0b",borderRadius:2,width:`${(c.total/ingresoTotal)*100}%`}}/>
                </div>
              </div>
            ))
          }
        </div>
      </div>

      {/* Últimas ventas */}
      <div className="card">
        <div style={{fontSize:10,color:"#444",letterSpacing:".1em",textTransform:"uppercase",fontWeight:600,marginBottom:14}}>Últimas ventas del período</div>
        {ventasFiltradas.slice(0,10).map((v,i)=>(
          <div key={v.id} style={{display:"flex",justifyContent:"space-between",alignItems:"center",padding:"10px 0",borderBottom:i<Math.min(9,ventasFiltradas.length-1)?"1px solid #1a1a1a":"none"}}>
            <div>
              <span style={{fontSize:12,color:"#ccc",fontWeight:500}}>{v.clienteNombre||"—"}</span>
              <span style={{fontSize:11,color:"#444",marginLeft:8}}>{v.productoNombre||"—"} × {v.cantidad}</span>
              <span style={{fontSize:10,color:"#333",marginLeft:8}}>{v.canal}</span>
            </div>
            <div style={{textAlign:"right"}}>
              <div style={{fontSize:13,fontWeight:700,color:"#4b7d0b"}}>{fmtARS(v.precioTotal||0)}</div>
              <div style={{fontSize:10,color:"#333"}}>{v.fecha?new Date(v.fecha).toLocaleDateString("es-AR",{day:"2-digit",month:"short"}):""}</div>
            </div>
          </div>
        ))}
        {ventasFiltradas.length===0&&<div style={{color:"#333",fontSize:12,textAlign:"center",padding:"12px 0"}}>Sin ventas en este período.</div>}
      </div>
    </div>
  );
}
